import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, FileText } from "lucide-react";
import { supabase } from "../lib/supabase";
import { toast } from "react-hot-toast";

interface AgentDossierProps {
  agent: any;
  onClose?: () => void;
  onStartChat: () => void;
  currentUserId: string;
  embedded?: boolean;
  userBranch?: string;
}

export const AgentDossier: React.FC<AgentDossierProps> = ({
  agent,
  onClose,
  onStartChat,
  currentUserId,
  embedded = false,
  userBranch,
}) => {
  const [bio, setBio] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (agent?.user_id) {
      fetchAgentDetails();
    }
  }, [agent, currentUserId]);

  const fetchAgentDetails = async () => {
    try {
      // Fetch Bio
      const { data: profileData } = await supabase
        .from("staff_profiles")
        .select("bio")
        .eq("user_id", agent.user_id)
        .single();

      if (profileData) {
        setBio(profileData.bio || "Data Classified. No public records found.");
      }
    } catch (error) {
      console.error("Error fetching details:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className={`
            flex flex-col bg-[#0a0a09] overflow-hidden relative font-sans
            ${
              embedded
                ? "w-full h-full rounded-2xl border border-white/5"
                : "fixed inset-0 z-50 rounded-none"
            }
        `}
    >
      {!embedded && (
        <button
          onClick={onClose}
          className="absolute top-6 right-6 z-50 p-2 bg-black/50 text-white rounded-full hover:bg-white/10"
        >
          <X size={20} />
        </button>
      )}

      {/* --- HEADER --- */}
      <div className="relative h-64 shrink-0">
        <div className="absolute inset-0 bg-gradient-to-b from-amber-900/40 via-[#0a0a09] to-[#0a0a09]">
          <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] mix-blend-overlay" />
        </div>

        <div className="absolute inset-x-0 bottom-0 p-6 flex flex-col items-center">
          <motion.div
            initial={{ scale: 0.5, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="w-32 h-32 rounded-full p-1 bg-gradient-to-b from-amber-400 to-amber-900 shadow-[0_0_40px_rgba(245,158,11,0.3)] relative z-10"
          >
            <img
              src={
                agent.avatar_url ||
                `https://ui-avatars.com/api/?name=${agent.full_name}&background=f59e0b&color=000`
              }
              className="w-full h-full rounded-full object-cover border-4 border-[#0a0a09]"
            />
            {agent.is_online && (
              <div className="absolute bottom-2 right-2 w-6 h-6 bg-emerald-500 border-4 border-[#0a0a09] rounded-full shadow-[0_0_10px_#10b981]" />
            )}
          </motion.div>

          <h1 className="mt-4 text-2xl font-black text-white uppercase tracking-tight text-center">
            {agent.full_name}
          </h1>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">
              {agent.branch_assigned || "Global"}
            </span>
          </div>
        </div>
      </div>

      {/* --- CONTENT --- */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-6 relative">
        <motion.div
          key="profile"
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: 20 }}
          className="space-y-6"
        >
          {/* Bio */}
          <div className="space-y-2">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest flex items-center gap-2">
              <FileText size={12} /> Bio
            </h3>
            <div className="p-5 rounded-2xl bg-white/5 border border-white/10 text-sm text-gray-300 leading-relaxed italic">
              "{bio}"
            </div>
          </div>

          <button
            onClick={onStartChat}
            className="w-full py-4 rounded-xl bg-white text-black font-black uppercase tracking-widest text-xs hover:bg-gray-200 transition-colors shadow-lg"
          >
            Start Chat
          </button>
        </motion.div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from "react";
import {
  Users,
  MapPin,
  TrendingUp,
  RefreshCw,
  Activity,
  Briefcase,
  UserCircle,
  Globe,
  FileSpreadsheet,
  ChevronLeft,
  ChevronRight,
  Download,
  AlertTriangle,
  CheckCircle,
  BookOpen,
  Target,
  X,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../lib/supabase";
import toast from "react-hot-toast";
import { format, startOfMonth, endOfMonth, subMonths } from "date-fns";
import { useBranch } from "../hooks/useBranch";
import { useAuth } from "../hooks/useAuth";
import { formatDateForIST } from "../utils/dateUtils";

interface CandidateAnalysisProps {
  onClose?: () => void;
}

interface CalendarSession {
  id: number;
  date: string;
  client_name: string;
  exam_name: string;
  candidate_count: number;
  branch_location?: string;
}

interface DiscrepancyInfo {
  clientName: string;
  examName: string;
  calendarCount: number;
  registerCount: number;
  difference: number;
  status: "match" | "shortage" | "excess";
}

export const CandidateAnalysis: React.FC<CandidateAnalysisProps> = ({
  onClose,
}) => {
  const { profile } = useAuth();
  const { activeBranch } = useBranch();
  const [loading, setLoading] = useState(true);
  const [candidates, setCandidates] = useState<any[]>([]);
  const [calendarSessions, setCalendarSessions] = useState<CalendarSession[]>(
    []
  );
  const [selectedView, setSelectedView] = useState<
    "overview" | "staff" | "discrepancy"
  >("overview");
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const isGlobalView = activeBranch === "global" || !activeBranch;

  // Elegant Teal/Cyan Neumorphic Theme
  const neumorphicBase = "bg-gradient-to-br from-[#0a2a2a] to-[#051a1a]";
  const neumorphicCard =
    "bg-gradient-to-br from-[#0f3535] to-[#082424] shadow-[8px_8px_24px_rgba(0,0,0,0.5),-4px_-4px_16px_rgba(50,150,150,0.02)] rounded-2xl border border-teal-500/10";
  const neumorphicCardLight =
    "bg-gradient-to-br from-[#134040] to-[#0a2a2a] shadow-[6px_6px_20px_rgba(0,0,0,0.4),-3px_-3px_12px_rgba(50,150,150,0.02)] rounded-xl border border-teal-500/10";
  const neumorphicBtn =
    "px-5 py-2.5 rounded-xl font-bold transition-all active:scale-95 shadow-[4px_4px_12px_rgba(0,0,0,0.4),-2px_-2px_8px_rgba(50,150,150,0.02)] bg-gradient-to-br from-[#134040] to-[#0a2a2a] text-gray-300 flex items-center gap-2 hover:text-teal-400 border border-teal-500/10";
  const neumorphicBtnActive =
    "px-5 py-2.5 rounded-xl font-bold transition-all shadow-[inset_4px_4px_12px_rgba(0,0,0,0.5),inset_-2px_-2px_8px_rgba(50,150,150,0.02)] bg-gradient-to-br from-[#0a2a2a] to-[#051a1a] text-teal-400 flex items-center gap-2 border border-teal-500/20";
  const neumorphicInset =
    "shadow-[inset_4px_4px_12px_rgba(0,0,0,0.5),inset_-2px_-2px_8px_rgba(50,150,150,0.02)] bg-gradient-to-br from-[#082424] to-[#051a1a] rounded-xl border border-teal-500/10";

  // Client color mapping for teal theme
  const clientColors: {
    [key: string]: { bg: string; text: string; border: string };
  } = {
    PROMETRIC: {
      bg: "from-rose-600/20 to-rose-800/20",
      text: "text-rose-400",
      border: "border-rose-500/30",
    },
    PSI: {
      bg: "from-emerald-600/20 to-emerald-800/20",
      text: "text-emerald-400",
      border: "border-emerald-500/30",
    },
    PEARSON: {
      bg: "from-sky-600/20 to-sky-800/20",
      text: "text-sky-400",
      border: "border-sky-500/30",
    },
    ITTS: {
      bg: "from-amber-600/20 to-amber-800/20",
      text: "text-amber-400",
      border: "border-amber-500/30",
    },
    OTHER: {
      bg: "from-slate-600/20 to-slate-800/20",
      text: "text-slate-400",
      border: "border-slate-500/30",
    },
  };

  useEffect(() => {
    fetchData();
  }, [currentMonth, activeBranch]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const monthStart = startOfMonth(currentMonth);
      const monthEnd = endOfMonth(currentMonth);

      // Fetch ALL candidates (from beginning to now) for the selected branch
      let candidateQuery = supabase.from("candidates").select("*");

      if (!isGlobalView) {
        candidateQuery = candidateQuery.eq("branch_location", activeBranch);
      }

      const { data: candidateData, error: candidateError } =
        await candidateQuery.order("created_at", { ascending: false });
      if (candidateError) throw candidateError;

      // Fetch staff profiles for name mapping
      const { data: profiles } = await supabase
        .from("staff_profiles")
        .select("user_id, full_name");
      const profileMap = (profiles || []).reduce((acc: any, p) => {
        acc[p.user_id] = p.full_name;
        return acc;
      }, {});

      const enrichedCandidates = (candidateData || []).map((c: any) => ({
        ...c,
        staff_name: profileMap[c.user_id] || "System/Legacy",
      }));

      setCandidates(enrichedCandidates);

      // Fetch calendar sessions for the selected month (for comparison)
      let calendarQuery = supabase
        .from("calendar_sessions")
        .select("*")
        .gte("date", formatDateForIST(monthStart))
        .lte("date", formatDateForIST(monthEnd));

      if (!isGlobalView) {
        calendarQuery = calendarQuery.eq("branch_location", activeBranch);
      }

      const { data: calendarData, error: calendarError } = await calendarQuery;
      if (calendarError) console.warn("Calendar fetch error:", calendarError);

      setCalendarSessions((calendarData as CalendarSession[]) || []);
    } catch (error) {
      console.error("Error fetching analysis data:", error);
      toast.error("Failed to load analysis data");
    } finally {
      setLoading(false);
    }
  };

  const normalizeClientName = (name: string): string => {
    const upper = (name || "").toUpperCase();
    if (upper.includes("PEARSON") || upper.includes("VUE")) return "PEARSON";
    if (upper.includes("PSI")) return "PSI";
    if (upper.includes("PROMETRIC")) return "PROMETRIC";
    if (upper.includes("ITTS")) return "ITTS";
    return "OTHER";
  };

  const getClientColor = (client: string) => {
    return clientColors[normalizeClientName(client)] || clientColors["OTHER"];
  };

  const extractLocation = (address: string): string => {
    if (!address) return "Not Specified";
    const parts = address.split(",");
    // Try to get city (usually second to last or last part)
    if (parts.length >= 2) {
      return (
        parts[parts.length - 2]?.trim() ||
        parts[parts.length - 1]?.trim() ||
        "Unknown"
      );
    }
    return parts[0]?.trim() || "Unknown";
  };

  // Filter candidates by current month for comparison
  const monthCandidates = useMemo(() => {
    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(currentMonth);
    return candidates.filter((c) => {
      const examDate = c.exam_date ? new Date(c.exam_date) : null;
      if (!examDate) return false;
      return examDate >= monthStart && examDate <= monthEnd;
    });
  }, [candidates, currentMonth]);

  // Calculate comprehensive metrics
  const metrics = useMemo(() => {
    const clientStats: Record<string, number> = {};
    const examStats: Record<string, { count: number; client: string }> = {};
    const locationStats: Record<string, number> = {};
    const staffStats: Record<string, number> = {};
    const monthlyStats: Record<string, { candidates: number; month: string }> =
      {};

    // Process ALL candidates for totals
    candidates.forEach((c) => {
      // Client stats
      const client = normalizeClientName(c.client_name);
      clientStats[client] = (clientStats[client] || 0) + 1;

      // Exam stats
      const exam = c.exam_name || "Unknown Exam";
      if (!examStats[exam]) {
        examStats[exam] = { count: 0, client: c.client_name || "Unknown" };
      }
      examStats[exam].count += 1;

      // Location/Address stats (extract city/district)
      const address = c.address || "";
      const location = extractLocation(address);
      locationStats[location] = (locationStats[location] || 0) + 1;

      // Staff contribution
      const staff = c.staff_name || "Unknown";
      staffStats[staff] = (staffStats[staff] || 0) + 1;

      // Monthly breakdown
      if (c.exam_date) {
        const monthKey = format(new Date(c.exam_date), "yyyy-MM");
        const monthLabel = format(new Date(c.exam_date), "MMM yyyy");
        if (!monthlyStats[monthKey]) {
          monthlyStats[monthKey] = { candidates: 0, month: monthLabel };
        }
        monthlyStats[monthKey].candidates += 1;
      }
    });

    return {
      clientStats,
      examStats,
      locationStats,
      staffStats,
      monthlyStats,
      totalCandidates: candidates.length,
      monthCandidates: monthCandidates.length,
    };
  }, [candidates, monthCandidates]);

  // Calculate discrepancies between Calendar and Register
  const discrepancies = useMemo((): DiscrepancyInfo[] => {
    const calendarMap: Record<
      string,
      { client: string; exam: string; count: number }
    > = {};

    // Group calendar sessions by client + exam
    calendarSessions.forEach((session) => {
      const key = `${normalizeClientName(session.client_name)}_${
        session.exam_name || "General"
      }`;
      if (!calendarMap[key]) {
        calendarMap[key] = {
          client: normalizeClientName(session.client_name),
          exam: session.exam_name || "General",
          count: 0,
        };
      }
      calendarMap[key].count += session.candidate_count;
    });

    // Group register candidates by client + exam for the same month
    const registerMap: Record<string, number> = {};
    monthCandidates.forEach((c) => {
      const key = `${normalizeClientName(c.client_name)}_${
        c.exam_name || "General"
      }`;
      registerMap[key] = (registerMap[key] || 0) + 1;
    });

    // Build discrepancy list
    const result: DiscrepancyInfo[] = [];
    const allKeys = new Set([
      ...Object.keys(calendarMap),
      ...Object.keys(registerMap),
    ]);

    allKeys.forEach((key) => {
      const calendarEntry = calendarMap[key];
      const registerCount = registerMap[key] || 0;
      const calendarCount = calendarEntry?.count || 0;
      const difference = registerCount - calendarCount;

      if (calendarEntry || registerCount > 0) {
        result.push({
          clientName: calendarEntry?.client || key.split("_")[0],
          examName: calendarEntry?.exam || key.split("_")[1] || "General",
          calendarCount,
          registerCount,
          difference,
          status:
            difference === 0 ? "match" : difference > 0 ? "excess" : "shortage",
        });
      }
    });

    return result.sort(
      (a, b) => Math.abs(b.difference) - Math.abs(a.difference)
    );
  }, [calendarSessions, monthCandidates]);

  const navigateMonth = (direction: "prev" | "next") => {
    const newDate = new Date(currentMonth);
    if (direction === "prev") {
      newDate.setMonth(newDate.getMonth() - 1);
    } else {
      newDate.setMonth(newDate.getMonth() + 1);
    }
    setCurrentMonth(newDate);
  };

  const exportReport = () => {
    const monthName = format(currentMonth, "MMMM yyyy");
    const centerName = isGlobalView
      ? "ALL CENTERS"
      : activeBranch.toUpperCase();

    let report = `
ΓòöΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòù
Γòæ              FETS REGISTER ANALYSIS REPORT                        Γòæ
Γòæ                    ${centerName.padEnd(20)}                        Γòæ
ΓòÜΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓò¥

Generated: ${new Date().toLocaleString("en-IN")}
Analysis Period: From Beginning to ${format(new Date(), "dd MMM yyyy")}
Comparison Month: ${monthName}

ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü

                        EXECUTIVE SUMMARY
ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü

Total Candidates (All Time): ${metrics.totalCandidates}
Candidates This Month:       ${metrics.monthCandidates}
Discrepancies Found:         ${
      discrepancies.filter((d) => d.status !== "match").length
    }

ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü

                     CLIENT-WISE BREAKDOWN
ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü
`;

    Object.entries(metrics.clientStats)
      .sort(([, a], [, b]) => b - a)
      .forEach(([client, count]) => {
        report += `
  ${client.padEnd(20)}: ${count.toString().padStart(5)} Candidates`;
      });

    report += `

ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü

                      EXAM-WISE BREAKDOWN
ΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöüΓöü
`;

    Object.entries(metrics.examStats)
      .sort(([, a], [, b]) => b.count - a.count)
      .slice(0, 15)
      .forEach(([exam, data]) => {
        report += `
  ${exam.substring(0, 30).padEnd(30)}: ${data.count.toString().padStart(5)} (${
          data.client
        })`;
