                key="discrepancy"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                className="space-y-8"
              >
                {/* Summary Cards */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className={`${neumorphicCard} p-6`}>
                    <div className="flex items-center gap-3 mb-4">
                      <CheckCircle size={24} className="text-emerald-400" />
                      <span className="text-gray-400 font-bold uppercase text-xs">
                        Matched
                      </span>
                    </div>
                    <p className="text-4xl font-black text-emerald-400">
                      {discrepancies.filter((d) => d.status === "match").length}
                    </p>
                  </div>
                  <div className={`${neumorphicCard} p-6`}>
                    <div className="flex items-center gap-3 mb-4">
                      <AlertTriangle size={24} className="text-rose-400" />
                      <span className="text-gray-400 font-bold uppercase text-xs">
                        Shortage
                      </span>
                    </div>
                    <p className="text-4xl font-black text-rose-400">
                      {
                        discrepancies.filter((d) => d.status === "shortage")
                          .length
                      }
                    </p>
                  </div>
                  <div className={`${neumorphicCard} p-6`}>
                    <div className="flex items-center gap-3 mb-4">
                      <TrendingUp size={24} className="text-amber-400" />
                      <span className="text-gray-400 font-bold uppercase text-xs">
                        Excess
                      </span>
                    </div>
                    <p className="text-4xl font-black text-amber-400">
                      {
                        discrepancies.filter((d) => d.status === "excess")
                          .length
                      }
                    </p>
                  </div>
                </div>

                {/* Discrepancy Table */}
                <div className={`${neumorphicCard} p-8`}>
                  <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-gradient-to-br from-rose-500/20 to-rose-600/20 rounded-lg text-rose-400">
                        <Target size={24} />
                      </div>
                      <div>
                        <h3 className="text-xl font-black text-white">
                          Calendar vs Register Comparison
                        </h3>
                        <p className="text-xs text-gray-500">
                          Comparing {format(currentMonth, "MMMM yyyy")} data
                        </p>
                      </div>
                    </div>
                  </div>

                  {discrepancies.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-16">
                      <CheckCircle
                        size={48}
                        className="text-emerald-400 mb-4"
                      />
                      <p className="text-lg font-bold text-white">
                        No data to compare
                      </p>
                      <p className="text-gray-500 text-sm">
                        No calendar sessions or register entries found for this
                        month
                      </p>
                    </div>
                  ) : (
                    <div className="overflow-x-auto">
                      <table className="w-full">
                        <thead>
                          <tr className="border-b border-white/10">
                            <th className="text-left py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Client
                            </th>
                            <th className="text-left py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Exam
                            </th>
                            <th className="text-center py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Calendar
                            </th>
                            <th className="text-center py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Register
                            </th>
                            <th className="text-center py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Difference
                            </th>
                            <th className="text-center py-4 px-4 font-bold text-gray-500 text-xs uppercase tracking-wider">
                              Status
                            </th>
                          </tr>
                        </thead>
                        <tbody>
                          {discrepancies.map((d, idx) => {
                            const color = getClientColor(d.clientName);
                            return (
                              <tr
                                key={idx}
                                className="border-b border-white/5 hover:bg-white/5 transition-colors"
                              >
                                <td className="py-4 px-4">
                                  <span className={`font-bold ${color.text}`}>
                                    {d.clientName}
                                  </span>
                                </td>
                                <td className="py-4 px-4 text-gray-300 text-sm">
                                  {d.examName}
                                </td>
                                <td className="text-center py-4 px-4 text-gray-400 font-medium">
                                  {d.calendarCount}
                                </td>
                                <td className="text-center py-4 px-4 text-gray-400 font-medium">
                                  {d.registerCount}
                                </td>
                                <td className="text-center py-4 px-4">
                                  <span
                                    className={`font-black ${
                                      d.difference === 0
                                        ? "text-emerald-400"
                                        : d.difference > 0
                                        ? "text-amber-400"
                                        : "text-rose-400"
                                    }`}
                                  >
                                    {d.difference > 0 ? "+" : ""}
                                    {d.difference}
                                  </span>
                                </td>
                                <td className="text-center py-4 px-4">
                                  <span
                                    className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                                      d.status === "match"
                                        ? "bg-emerald-500/20 text-emerald-400"
                                        : d.status === "excess"
                                        ? "bg-amber-500/20 text-amber-400"
                                        : "bg-rose-500/20 text-rose-400"
                                    }`}
                                  >
                                    {d.status}
                                  </span>
                                </td>
                              </tr>
                            );
                          })}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>

                {/* Alert for mismatches */}
                {discrepancies.filter((d) => d.status === "shortage").length >
                  0 && (
                  <div
                    className={`${neumorphicCard} p-6 border-l-4 border-rose-500`}
                  >
                    <div className="flex items-center gap-4">
                      <AlertTriangle size={24} className="text-rose-400" />
                      <div>
                        <h4 className="font-bold text-rose-400">
                          Action Required
                        </h4>
                        <p className="text-gray-400 text-sm">
                          {
                            discrepancies.filter((d) => d.status === "shortage")
                              .length
                          }{" "}
                          exam(s) show fewer registered candidates than
                          scheduled in the calendar. Please verify the register
                          entries are complete.
                        </p>
                      </div>
                    </div>
                  </div>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        )}
      </div>
    </motion.div>
  );
};

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Building2,
  Plus,
  Trash2,
  Edit3,
  MapPin,
  GraduationCap,
  Save,
  X,
  Search,
  ChevronRight,
  Hash,
  Palette,
} from "lucide-react";
import { supabase } from "../lib/supabase";
import { toast } from "react-hot-toast";

export interface Client {
  id: string;
  name: string;
  color: string;
  logo_url?: string;
}

export interface ClientExam {
  id: string;
  client_id: string;
  name: string;
  locations: string[];
}

const BRANCHES = ["calicut", "cochin", "kannur"];

const CLIENT_COLORS = [
  { name: "Blue", value: "blue" },
  { name: "Green", value: "green" },
  { name: "Amber", value: "amber" },
  { name: "Rose", value: "rose" },
  { name: "Purple", value: "purple" },
  { name: "Indigo", value: "indigo" },
  { name: "Teal", value: "teal" },
  { name: "Orange", value: "orange" },
];

// Premium Classic Theme - Matching Management Page
const THEME = {
  bgPrimary: "#0f1419",
  bgSecondary: "#1a2332",
  bgTertiary: "#243044",
  bgCard: "#1e2a3a",
  bgHover: "#2a3a4d",
  gold: "#d4a853",
  goldLight: "#e8c47a",
  goldDark: "#b8923f",
  goldMuted: "rgba(212, 168, 83, 0.15)",
  textPrimary: "#f8fafc",
  textSecondary: "#94a3b8",
  textMuted: "#64748b",
  border: "rgba(255, 255, 255, 0.08)",
  shadow: "0 10px 40px rgba(0, 0, 0, 0.4)",
  shadowGold: "0 0 30px rgba(212, 168, 83, 0.2)",
};

export function ClientControl() {
  const [clients, setClients] = useState<Client[]>([]);
  const [exams, setExams] = useState<ClientExam[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");

  const [showAddClient, setShowAddClient] = useState(false);
  const [newClientName, setNewClientName] = useState("");
  const [newClientColor, setNewClientColor] = useState("amber");

  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [showAddExam, setShowAddExam] = useState(false);
  const [newExam, setNewExam] = useState({
    name: "",
    locations: [] as string[],
  });

  const [editingClient, setEditingClient] = useState<Client | null>(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const { data: clientsData } = await supabase
        .from("clients")
        .select("*")
        .order("name");
      const { data: examsData } = await supabase
        .from("client_exams")
        .select("*")
        .order("name");
      setClients(clientsData || []);
      setExams(examsData || []);
      if (clientsData && clientsData.length > 0 && !selectedClientId) {
        setSelectedClientId(clientsData[0].id);
      }
    } catch (error) {
      toast.error("Failed to sync client data");
    } finally {
      setLoading(false);
    }
  };

  const handleAddClient = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClientName.trim()) return;
    try {
      const { error } = await supabase
        .from("clients")
        .insert([{ name: newClientName.toUpperCase(), color: newClientColor }]);
      if (error) throw error;
      toast.success("Client added");
      setNewClientName("");
      setShowAddClient(false);
      fetchData();
    } catch (error) {
      toast.error("Failed to add client");
    }
  };

  const handleUpdateClient = async () => {
    if (!editingClient) return;
    try {
      const { error } = await supabase
        .from("clients")
        .update({
          name: editingClient.name.toUpperCase(),
          color: editingClient.color,
        })
        .eq("id", editingClient.id);
      if (error) throw error;
      toast.success("Client updated");
      setEditingClient(null);
      fetchData();
    } catch (error) {
      toast.error("Failed to update");
    }
  };

  const handleDeleteClient = async (id: string) => {
    if (!confirm("Delete this client and all exams?")) return;
    try {
      await supabase.from("client_exams").delete().eq("client_id", id);
      await supabase.from("clients").delete().eq("id", id);
      toast.success("Client removed");
      if (selectedClientId === id) setSelectedClientId(null);
      fetchData();
    } catch (error) {
      toast.error("Failed to remove");
    }
  };

  const handleAddExam = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedClientId || !newExam.name.trim()) return;
    try {
      const { error } = await supabase
        .from("client_exams")
        .insert([
          {
            client_id: selectedClientId,
            name: newExam.name.toUpperCase(),
            locations: newExam.locations,
          },
        ]);
      if (error) throw error;
      toast.success("Exam added");
      setNewExam({ name: "", locations: [] });
      setShowAddExam(false);
      fetchData();
    } catch (error) {
      toast.error("Failed to add exam");
    }
  };

  const handleDeleteExam = async (examId: string) => {
    if (!confirm("Delete this exam?")) return;
    try {
      await supabase.from("client_exams").delete().eq("id", examId);
      toast.success("Exam removed");
      fetchData();
    } catch (error) {
      toast.error("Failed to remove");
    }
  };

  const toggleLocation = (loc: string) => {
    setNewExam((prev) => ({
      ...prev,
      locations: prev.locations.includes(loc)
        ? prev.locations.filter((l) => l !== loc)
        : [...prev.locations, loc],
    }));
  };

  const getColorStyle = (color: string) => {
    const colors: Record<string, { bg: string; text: string }> = {
      blue: { bg: "rgba(59, 130, 246, 0.2)", text: "#60a5fa" },
      green: { bg: "rgba(34, 197, 94, 0.2)", text: "#4ade80" },
      amber: { bg: "rgba(245, 158, 11, 0.2)", text: "#fbbf24" },
      rose: { bg: "rgba(244, 63, 94, 0.2)", text: "#fb7185" },
      purple: { bg: "rgba(168, 85, 247, 0.2)", text: "#c084fc" },
      indigo: { bg: "rgba(99, 102, 241, 0.2)", text: "#818cf8" },
      teal: { bg: "rgba(20, 184, 166, 0.2)", text: "#2dd4bf" },
      orange: { bg: "rgba(249, 115, 22, 0.2)", text: "#fb923c" },
    };
    return colors[color] || colors.amber;
  };

  const filteredClients = clients.filter((c) =>
    c.name.toLowerCase().includes(searchQuery.toLowerCase())
  );
  const activeClient = clients.find((c) => c.id === selectedClientId);
  const activeClientExams = exams.filter(
    (e) => e.client_id === selectedClientId
  );

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div
          className="animate-spin rounded-full h-10 w-10 border-2"
          style={{ borderColor: THEME.bgTertiary, borderTopColor: THEME.gold }}
        />
      </div>
    );
  }

  return (
    <div
      className="flex gap-6 h-full"
      style={{ fontFamily: "'Inter', sans-serif" }}
    >
      {/* Left Sidebar - Client List */}
      <aside
        className="w-80 flex flex-col rounded-2xl overflow-hidden shrink-0"
        style={{
          background: THEME.bgSecondary,
          border: `1px solid ${THEME.border}`,
        }}
      >
        {/* Header */}
        <div className="p-5 border-b" style={{ borderColor: THEME.border }}>
          <div className="flex items-center justify-between mb-4">
            <h2
              className="text-lg font-bold"
              style={{
                fontFamily: "'Playfair Display', serif",
                color: THEME.textPrimary,
              }}
            >
              Clients
            </h2>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowAddClient(true)}
              className="w-9 h-9 rounded-lg flex items-center justify-center"
              style={{ background: THEME.gold, color: THEME.bgPrimary }}
            >
              <Plus size={18} />
            </motion.button>
          </div>

          {/* Search */}
          <div className="relative">
            <Search
              size={16}
              className="absolute left-3 top-1/2 -translate-y-1/2"
              style={{ color: THEME.textMuted }}
            />
            <input
              type="text"
              placeholder="Search clients..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 rounded-lg text-sm font-medium focus:outline-none"
              style={{
                background: THEME.bgTertiary,
                color: THEME.textPrimary,
                border: `1px solid ${THEME.border}`,
              }}
            />
          </div>
        </div>

        {/* Client List */}
        <div className="flex-1 overflow-y-auto p-3 premium-scrollbar">
          <div className="space-y-2">
            {filteredClients.map((client) => {
              const colorStyle = getColorStyle(client.color);
              return (
                <motion.button
                  key={client.id}
                  onClick={() => setSelectedClientId(client.id)}
                  whileHover={{ x: 4 }}
                  className="w-full p-4 rounded-xl text-left transition-all flex items-center gap-3 group"
                  style={{
                    background:
                      selectedClientId === client.id
                        ? THEME.bgTertiary
                        : "transparent",
                    border:
                      selectedClientId === client.id
                        ? `1px solid ${THEME.gold}40`
                        : "1px solid transparent",
                  }}
                >
                  <div
                    className="w-10 h-10 rounded-lg flex items-center justify-center font-bold text-sm shrink-0"
                    style={{
                      background: colorStyle.bg,
                      color: colorStyle.text,
                    }}
                  >
                    <Hash size={16} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p
                      className="font-semibold text-sm truncate"
                      style={{ color: THEME.textPrimary }}
                    >
                      {client.name}
                    </p>
                    <p className="text-xs" style={{ color: THEME.textMuted }}>
                      {exams.filter((e) => e.client_id === client.id).length}{" "}
                      exams
                    </p>
                  </div>
                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setEditingClient(client);
                      }}
                      className="p-1.5 rounded"
                      style={{ color: THEME.textSecondary }}
                    >
                      <Edit3 size={14} />
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDeleteClient(client.id);
                      }}
                      className="p-1.5 rounded text-red-400"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </motion.button>
              );
            })}
            {filteredClients.length === 0 && (
              <div className="py-12 text-center">
                <Building2
                  size={32}
                  className="mx-auto mb-2"
                  style={{ color: THEME.textMuted }}
                />
                <p className="text-sm" style={{ color: THEME.textMuted }}>
                  No clients found
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div
          className="p-4 border-t text-center"
          style={{ borderColor: THEME.border }}
        >
          <p className="text-xs" style={{ color: THEME.textMuted }}>
            {clients.length} clients total
          </p>
        </div>
      </aside>

      {/* Main Content - Exams */}
      <div
        className="flex-1 flex flex-col rounded-2xl overflow-hidden"
        style={{
          background: THEME.bgSecondary,
          border: `1px solid ${THEME.border}`,
        }}
      >
        {activeClient ? (
          <>
            {/* Client Header */}
            <div
              className="p-6 flex items-center gap-6 border-b"
              style={{ borderColor: THEME.border, background: THEME.bgCard }}
            >
              <div
                className="w-16 h-16 rounded-2xl flex items-center justify-center text-2xl font-bold shrink-0"
                style={{
                  background: `linear-gradient(135deg, ${THEME.gold}, ${THEME.goldDark})`,
                  color: THEME.bgPrimary,
                  boxShadow: THEME.shadowGold,
                }}
              >
                <Building2 size={28} />
              </div>
              <div className="flex-1">
                <h2
                  className="text-2xl font-bold"
                  style={{
                    fontFamily: "'Playfair Display', serif",
                    color: THEME.textPrimary,
                  }}
                >
                  {activeClient.name}
                </h2>
                <p
                  className="text-sm mt-1"
                  style={{ color: THEME.textSecondary }}
                >
                  {activeClientExams.length} exam
                  {activeClientExams.length !== 1 ? "s" : ""} configured
                </p>
              </div>
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={() => setShowAddExam(true)}
                className="px-5 py-2.5 rounded-lg font-semibold text-sm flex items-center gap-2"
                style={{ background: THEME.gold, color: THEME.bgPrimary }}
              >
                <Plus size={16} /> Add Exam
              </motion.button>
            </div>

            {/* Exams Grid */}
            <div className="flex-1 overflow-y-auto p-6 premium-scrollbar">
              {activeClientExams.length > 0 ? (
                <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-4">
                  {activeClientExams.map((exam) => (
                    <motion.div
                      key={exam.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      className="p-5 rounded-xl group"
                      style={{
                        background: THEME.bgTertiary,
                        border: `1px solid ${THEME.border}`,
                      }}
                    >
                      <div className="flex items-start justify-between mb-4">
                        <div className="flex items-center gap-3">
                          <div
                            className="w-10 h-10 rounded-lg flex items-center justify-center"
                            style={{
                              background: THEME.goldMuted,
                              color: THEME.gold,
                            }}
                          >
                            <GraduationCap size={18} />
                          </div>
                          <h4
                            className="font-semibold"
                            style={{ color: THEME.textPrimary }}
                          >
                            {exam.name}
                          </h4>
                        </div>
                        <button
                          onClick={() => handleDeleteExam(exam.id)}
                          className="p-2 rounded-lg opacity-0 group-hover:opacity-100 transition-all text-red-400"
                          style={{ background: "rgba(239, 68, 68, 0.1)" }}
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                      <div className="flex flex-wrap gap-2">
                        {exam.locations.length > 0 ? (
                          exam.locations.map((loc) => (
                            <span
                              key={loc}
                              className="px-2.5 py-1 rounded text-xs font-semibold uppercase flex items-center gap-1.5"
                              style={{
                                background: THEME.bgCard,
                                color: THEME.textSecondary,
                              }}
                            >
                              <MapPin size={10} style={{ color: THEME.gold }} />
                              {loc}
                            </span>
                          ))
                        ) : (
                          <span
                            className="text-xs italic"
                            style={{ color: THEME.textMuted }}
                          >
                            All locations
                          </span>
                        )}
                      </div>
                    </motion.div>
                  ))}
                </div>
              ) : (
                <div
                  className="h-full flex flex-col items-center justify-center rounded-xl border-2 border-dashed"
                  style={{ borderColor: THEME.border }}
                >
                  <GraduationCap size={48} style={{ color: THEME.textMuted }} />
                  <p
                    className="mt-4 font-semibold"
                    style={{ color: THEME.textPrimary }}
                  >
                    No exams configured
                  </p>
                  <p
                    className="text-sm mt-1"
                    style={{ color: THEME.textMuted }}
                  >
                    Add exams for this client
                  </p>
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center">
            <Building2 size={64} style={{ color: THEME.bgTertiary }} />
            <h3
              className="text-xl font-bold mt-6"
              style={{
                fontFamily: "'Playfair Display', serif",
                color: THEME.textPrimary,
              }}
            >
              Select a Client
            </h3>
            <p className="text-sm mt-2" style={{ color: THEME.textMuted }}>
              Choose from the list to manage exams
            </p>
          </div>
        )}
      </div>

      {/* Modals */}
      <AnimatePresence>
        {showAddClient && (
          <Modal title="Add Client" onClose={() => setShowAddClient(false)}>
            <form onSubmit={handleAddClient} className="space-y-5">
              <div>
                <label
                  className="block text-xs font-semibold uppercase tracking-wider mb-2"
                  style={{ color: THEME.textMuted }}
                >
                  Client Name
                </label>
                <input
                  type="text"
                  required
                  value={newClientName}
                  onChange={(e) => setNewClientName(e.target.value)}
                  placeholder="e.g. PEARSON VUE"
