              </div>
              <button
                type="submit"
                className="w-full py-3.5 rounded-xl font-semibold"
                style={{ background: THEME.gold, color: THEME.bgPrimary }}
              >
                Add Exam
              </button>
            </form>
          </Modal>
        )}
      </AnimatePresence>
    </div>
  );
}

// Reusable Modal Component
function Modal({
  title,
  onClose,
  children,
}: {
  title: string;
  onClose: () => void;
  children: React.ReactNode;
}) {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-center justify-center p-4"
      style={{ background: "rgba(0,0,0,0.8)", backdropFilter: "blur(10px)" }}
    >
      <motion.div
        initial={{ scale: 0.95, y: 20 }}
        animate={{ scale: 1, y: 0 }}
        exit={{ scale: 0.95, y: 20 }}
        className="w-full max-w-md rounded-2xl overflow-hidden"
        style={{
          background: THEME.bgSecondary,
          border: `1px solid ${THEME.border}`,
          boxShadow: THEME.shadow,
        }}
      >
        <div
          className="p-5 flex justify-between items-center border-b"
          style={{ borderColor: THEME.border, background: THEME.bgCard }}
        >
          <h3
            className="text-lg font-bold"
            style={{
              fontFamily: "'Playfair Display', serif",
              color: THEME.textPrimary,
            }}
          >
            {title}
          </h3>
          <button onClick={onClose} style={{ color: THEME.textMuted }}>
            <X size={20} />
          </button>
        </div>
        <div className="p-6">{children}</div>
      </motion.div>
    </motion.div>
  );
}

export async function getClientsAndExams(): Promise<{
  clients: Client[];
  exams: ClientExam[];
}> {
  const { data: clients } = await supabase
    .from("clients")
    .select("*")
    .order("name");
  const { data: exams } = await supabase
    .from("client_exams")
    .select("*")
    .order("name");
  return { clients: clients || [], exams: exams || [] };
}

