// Event Detail Modal Component
function EventDetailModal({
  event,
  isOpen,
  onClose,
  onEventUpdated,
}: {
  event: Event | null;
  isOpen: boolean;
  onClose: () => void;
  onEventUpdated: () => void;
}) {
  const { profile } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState({
    title: "",
    description: "",
    category: "",
    priority: "minor" as "critical" | "major" | "minor",
    status: "open" as
      | "open"
      | "assigned"
      | "in_progress"
      | "escalated"
      | "closed",
  });
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [updating, setUpdating] = useState(false);

  useEffect(() => {
    if (event) {
      setEditForm({
        title: event.title,
        description: event.description,
        category: event.category,
        priority: event.priority,
        status: event.status,
      });
    }
  }, [event]);

  if (!isOpen || !event) return null;

  const categoryConfig =
    EVENT_CATEGORIES.find((cat) => cat.id === event.category) ||
    EVENT_CATEGORIES[EVENT_CATEGORIES.length - 1];
  const Icon = categoryConfig.icon;

  const handleUpdate = async () => {
    setUpdating(true);
    try {
      const { error } = await supabase
        .from("incidents")
        .update({
          title: editForm.title,
          description: editForm.description,
          category: editForm.category,
          severity: editForm.priority,
          status: editForm.status,
          updated_at: new Date().toISOString(),
        })
        .eq("id", event.id);

      if (error) throw error;

      toast.success("Event updated successfully");
      setIsEditing(false);
      onEventUpdated();
    } catch (error) {
      console.error("Error updating event:", error);
      toast.error("Failed to update event");
    } finally {
      setUpdating(false);
    }
  };

  const handleDelete = async () => {
    try {
      const { error } = await supabase
        .from("incidents")
        .delete()
        .eq("id", event.id);

      if (error) throw error;

      toast.success("Event deleted successfully");
      onEventUpdated();
      onClose();
    } catch (error) {
      console.error("Error deleting event:", error);
      toast.error("Failed to delete event");
    }
  };

  const handleStatusChange = async (newStatus: typeof editForm.status) => {
    try {
      const updateData: any = {
        status: newStatus,
        updated_at: new Date().toISOString(),
      };

      if (newStatus === "closed") {
        updateData.completed_at = new Date().toISOString();
      }

      const { error } = await supabase
        .from("incidents")
        .update(updateData)
        .eq("id", event.id);

      if (error) throw error;

      toast.success(
        `Event ${newStatus === "closed" ? "closed" : "updated"} successfully`
      );
      onEventUpdated();
    } catch (error) {
      console.error("Error updating status:", error);
      toast.error("Failed to update status");
    }
  };

  const canEdit =
    profile?.id === event.reporter_id ||
    profile?.role === "admin" ||
    profile?.role === "super_admin";

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="bg-white rounded-2xl shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-hidden"
      >
        <div className="p-6 border-b border-gray-200">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div
                className={`w-12 h-12 ${categoryConfig.color} rounded-xl flex items-center justify-center`}
              >
                <Icon className="w-6 h-6 text-white" />
              </div>
              <div>
                {isEditing ? (
                  <input
                    type="text"
                    value={editForm.title}
                    onChange={(e) =>
                      setEditForm({ ...editForm, title: e.target.value })
                    }
                    className="text-xl font-bold text-gray-900 border-b-2 border-yellow-400 focus:outline-none"
                  />
                ) : (
                  <h2 className="text-xl font-bold text-gray-900">
                    {event.title}
                  </h2>
                )}
                <p className="text-gray-600">{categoryConfig.name}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              {canEdit && !isEditing && (
                <button
                  onClick={() => setIsEditing(true)}
                  className="p-2 rounded-lg hover:bg-gray-100 transition-colors"
                  title="Edit event"
                >
                  <Edit3 className="w-5 h-5 text-blue-600" />
                </button>
              )}
              <button
                onClick={onClose}
                className="p-2 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>

        <div className="p-6 max-h-[70vh] overflow-y-auto">
          <div className="space-y-6">
            {/* Event Details */}
            <div>
              <h3 className="font-semibold text-gray-900 mb-3">
                Event Details
              </h3>
              <div className="bg-gray-50 rounded-xl p-4">
                {isEditing ? (
                  <textarea
                    value={editForm.description}
                    onChange={(e) =>
                      setEditForm({ ...editForm, description: e.target.value })
                    }
                    className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-yellow-400 focus:border-transparent resize-none"
                    rows={4}
                  />
                ) : (
                  <p className="text-gray-700">{event.description}</p>
                )}
              </div>
            </div>

            {/* Metadata */}
            <div className="grid grid-cols-2 gap-6">
              {isEditing ? (
                <>
                  <div>
                    <h4 className="font-medium text-gray-900 mb-2">Category</h4>
                    <select
                      value={editForm.category}
                      onChange={(e) =>
                        setEditForm({ ...editForm, category: e.target.value })
