export const Frame = () => {
  const { user, profile } = useAuth();
  const { startCall } = useGlobalCall();
  const [activeTab, setActiveTab] = useState<"calls" | "schedule">("calls");
  const [groups, setGroups] = useState<any[]>([]);
  const [meetings, setMeetings] = useState<any[]>([]);
  const [staff, setStaff] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showNewGroup, setShowNewGroup] = useState(false);
  const [showNewMeeting, setShowNewMeeting] = useState(false);

  // Form States
  const [groupName, setGroupName] = useState("");
  const [groupDesc, setGroupDesc] = useState("");
  const [selectedMembers, setSelectedMembers] = useState<string[]>([]);
  const [meetingTitle, setMeetingTitle] = useState("");
  const [meetingDate, setMeetingDate] = useState("");
  const [meetingTime, setMeetingTime] = useState("");

  useEffect(() => {
    if (profile?.id) {
      fetchData();
      fetchStaff();
    }
  }, [profile?.id]);

  const fetchStaff = async () => {
    const { data } = await supabase
      .from("staff_profiles")
      .select("id, full_name, avatar_url, role")
      .order("full_name");
    if (data) setStaff(data);
  };

  const fetchData = async () => {
    if (!profile?.id) return;

    setIsLoading(true);
    try {
      const { data: memberships } = await supabase
        .from("workspace_group_members")
        .select("group_id")
        .eq("user_id", profile.id);

      const groupIds = memberships?.map((m) => m.group_id) || [];

      if (groupIds.length > 0) {
        const { data: myGroups } = await supabase
          .from("workspace_groups")
          .select("*")
          .in("id", groupIds);
        setGroups(myGroups || []);

        const { data: myMeetings } = await supabase
          .from("scheduled_meetings")
          .select("*")
          .in("group_id", groupIds)
          .gte("start_time", new Date().toISOString())
          .order("start_time", { ascending: true });

        setMeetings(myMeetings || []);
      } else {
        setGroups([]);
        setMeetings([]);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCreateGroup = async () => {
    if (!groupName) return toast.error("Check Name");
    try {
      const { data: grp } = await supabase
        .from("workspace_groups")
        .insert({
          name: groupName,
          description: groupDesc,
          branch_id: "Global",
          created_by: profile.id,
        })
        .select()
        .single();

      if (!grp) throw new Error();

      const members = [...new Set([profile.id, ...selectedMembers])].map(
        (uid) => ({
          group_id: grp.id,
          user_id: uid,
          role: uid === profile.id ? "admin" : "member",
        })
      );
      await supabase.from("workspace_group_members").insert(members);

      toast.success("Group Ready");
      setGroupName("");
      setGroupDesc("");
      setSelectedMembers([]);
      setShowNewGroup(false);
      fetchData();
    } catch {
      toast.error("Error Creating Group");
    }
  };

  const handleStartCall = (groupId: string) => {
    const group = groups.find((g) => g.id === groupId);
    supabase
      .from("workspace_group_members")
      .select("user_id")
      .eq("group_id", groupId)
      .then(({ data }) => {
        const ids =
          data?.map((m) => m.user_id).filter((id) => id !== profile.id) || [];
        if (ids.length) {
          toast.success(`Calling ${group.name}`);
          startCall(ids, "video");
        } else {
          toast.error("Group is empty");
        }
      });
  };

  const handleScheduleMeeting = async () => {
    if (!meetingTitle || !meetingDate || !meetingTime || !groups.length)
      return toast.error("Fill Details");
    try {
      await supabase.from("scheduled_meetings").insert({
        title: meetingTitle,
        start_time: new Date(`${meetingDate}T${meetingTime}`).toISOString(),
        created_by: profile.id,
        group_id: groups[0].id,
        room_url: `https://fets.live/meet/${Math.random()
          .toString(36)
          .substring(7)}`,
      });
      toast.success("Scheduled");
      setShowNewMeeting(false);
      fetchData();
    } catch {
      toast.error("Error Scheduling");
    }
  };

  if (isLoading)
    return (
      <div className="h-full bg-black flex items-center justify-center">
        <Loader2 className="animate-spin text-white/50" />
      </div>
    );

  return (
    <div className="h-full relative flex overflow-hidden font-sans select-none bg-black text-white">
      <LiquidBackground />

      {/* --- MAIN GLASS CONTAINER --- */}
      <div className="relative z-10 w-full h-full p-8 flex gap-8">
        {/* --- SIDEBAR NAVIGATION (Floating Glass) --- */}
        <GlassPanel className="w-28 flex flex-col items-center py-8 gap-4 shrink-0">
          <NavButton
            active={activeTab === "calls"}
            icon={Video}
            label="Calls"
            onClick={() => setActiveTab("calls")}
          />
          <NavButton
            active={activeTab === "schedule"}
            icon={Calendar}
            label="Schedule"
