                ) : (
                  <>
                    <input
                      value={meetingTitle}
                      onChange={(e) => setMeetingTitle(e.target.value)}
                      placeholder="Meeting Subject"
                      className="w-full bg-black/20 border border-white/10 rounded-2xl px-5 py-4 text-white placeholder-white/30 focus:outline-none focus:border-white/30"
                    />
                    <div className="grid grid-cols-2 gap-4">
                      <input
                        type="date"
                        value={meetingDate}
                        onChange={(e) => setMeetingDate(e.target.value)}
                        className="bg-black/20 border border-white/10 rounded-2xl px-4 py-4 text-white/80 focus:outline-none"
                      />
                      <input
                        type="time"
                        value={meetingTime}
                        onChange={(e) => setMeetingTime(e.target.value)}
                        className="bg-black/20 border border-white/10 rounded-2xl px-4 py-4 text-white/80 focus:outline-none"
                      />
                    </div>
                    <button
                      onClick={handleScheduleMeeting}
                      className="w-full py-4 mt-4 bg-white text-black rounded-2xl font-medium hover:shadow-[0_0_30px_rgba(255,255,255,0.3)] transition-all"
                    >
                      Confirm Schedule
                    </button>
                  </>
                )}
              </div>

              <button
                onClick={() => {
                  setShowNewGroup(false);
                  setShowNewMeeting(false);
                }}
                className="absolute top-6 right-6 p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors"
              >
                <X size={18} className="text-white/60" />
              </button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

