// --- Types ---

type PulseType = "Appreciation" | "Idea" | "Fun" | "General";

interface PulsePost {
  id: string;
  author_id: string;
  user_id?: string;
  content: string;
  post_type: PulseType;
  image_url?: string;
  branch_location: string;
  created_at: string;
  user?: {
    full_name: string;
    avatar_url?: string;
    role?: string;
  };
  likes?: any[];
  comments?: any[];
  _count?: {
    likes: number;
    comments: number;
  };
}

// --- Helpers ---

const getPulseTheme = (type: PulseType) => {
  switch (type) {
    case "Fun":
      return {
        bg: "bg-pink-50",
        border: "border-pink-200",
        accent: "bg-pink-500",
        text: "text-pink-900",
        shadow: "shadow-pink-100",
        icon: Smile,
        color: "#EC4899",
      };
    case "Appreciation":
      return {
        bg: "bg-emerald-50",
        border: "border-emerald-200",
        accent: "bg-emerald-500",
        text: "text-emerald-900",
        shadow: "shadow-emerald-100",
        icon: Heart,
        color: "#10B981",
      };
    case "Idea":
      return {
        bg: "bg-indigo-50",
        border: "border-indigo-200",
        accent: "bg-indigo-500",
        text: "text-indigo-900",
        shadow: "shadow-indigo-100",
        icon: Lightbulb,
        color: "#6366F1",
      };
    case "General":
    default:
      return {
        bg: "bg-slate-50",
        border: "border-slate-200",
        accent: "bg-slate-500",
        text: "text-slate-900",
        shadow: "shadow-slate-100",
        icon: Info,
        color: "#64748B",
      };
  }
};

// --- Modals ---

const CreatePostModal = ({
  onClose,
  onSuccess,
  profile,
  activeBranch,
}: {
  onClose: () => void;
  onSuccess: () => void;
  profile: any;
  activeBranch: string;
}) => {
  const [content, setContent] = useState("");
  const [type, setType] = useState<PulseType>("General");
  const [image, setImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const createPost = useCreatePost();
  const uploadImage = useUploadImage();

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImage(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim() && !image) return;

    setUploading(true);
    try {
      let finalImageUrl = null;

      if (image) {
        finalImageUrl = await uploadImage.mutateAsync(image);
      }

      await createPost.mutateAsync({
        content: content.trim(),
        user_id: profile?.user_id,
        post_type: type,
        branch_location: activeBranch || "global",
        image_url: finalImageUrl || undefined,
      });

      onSuccess();
      onClose();
    } catch (err: any) {
      // Error handled by hook
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
      <motion.div
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        className="w-full max-w-lg bg-white rounded-3xl shadow-2xl overflow-hidden border border-slate-100"
      >
        <div className="bg-white p-4 border-b border-slate-100 flex justify-between items-center">
          <span className="font-bold text-slate-800">Create new post</span>
          <button onClick={onClose} className="text-blue-500 font-bold text-sm">
            Cancel
          </button>
          {/* Just for layout balance */}
        </div>

        <form onSubmit={handleSubmit} className="p-0">
          <div className="p-4 flex gap-4">
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden shrink-0">
              <img
                src={
                  profile?.avatar_url ||
                  `https://ui-avatars.com/api/?name=${profile?.full_name}`
                }
                className="w-full h-full object-cover"
              />
            </div>
            <div className="flex-1">
              <textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder="Write a caption..."
                className="w-full h-24 resize-none outline-none text-slate-800 placeholder:text-slate-400 text-sm"
              />
              {previewUrl && (
                <div className="relative mt-2 rounded-xl overflow-hidden">
                  <img
                    src={previewUrl}
                    className="w-full max-h-60 object-cover"
                  />
                  <button
                    type="button"
                    onClick={() => {
                      setImage(null);
                      setPreviewUrl(null);
                    }}
                    className="absolute top-2 right-2 bg-black/50 text-white p-1 rounded-full"
                  >
                    <X size={14} />
                  </button>
                </div>
              )}
            </div>
          </div>

          <div className="px-4 pb-4">
            <div className="flex gap-2 overflow-x-auto no-scrollbar py-2">
              {(["General", "Appreciation", "Idea", "Fun"] as PulseType[]).map(
                (t) => (
                  <button
                    key={t}
                    type="button"
                    onClick={() => setType(t)}
                    className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-colors ${
                      type === t
                        ? "bg-slate-900 text-white"
                        : "bg-slate-100 text-slate-500"
                    }`}
                  >
                    {t}
                  </button>
                )
              )}
            </div>
          </div>

          <div className="p-4 border-t border-slate-100 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="p-2 text-slate-400 hover:text-slate-900 transition-colors"
              >
                <ImageIcon size={20} />
              </button>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                accept="image/*"
                className="hidden"
              />
              <button
                type="button"
                className="p-2 text-slate-400 hover:text-slate-900 transition-colors"
              >
                <Video size={20} />
              </button>
            </div>
            <button
              type="submit"
              disabled={uploading || (!content && !image)}
              className="text-blue-500 font-bold text-sm disabled:opacity-50"
            >
              {uploading ? "Sharing..." : "Share"}
            </button>
          </div>
        </form>
      </motion.div>
    </div>
  );
};

const PostDetailModal = ({
  post,
  onClose,
  profile,
}: {
  post: PulsePost;
  onClose: () => void;
  profile: any;
}) => {
  const theme = getPulseTheme(post.post_type);
  const toggleLike = useToggleLike();
  const addComment = useAddComment();
  const [comment, setComment] = useState("");
  const isLiked = post.likes?.some((l) => l.user_id === profile?.user_id);

  // Sort comments: oldest first
  const comments = [...(post.comments || [])].sort(
    (a, b) =>
      new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
  );

