import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Radio,
  Megaphone,
  AlertTriangle,
  Info,
  Clock,
  CheckCircle2,
  Zap,
} from "lucide-react";
import { supabase } from "../lib/supabase";
import { useBranch } from "../hooks/useBranch";
import { formatDistanceToNow } from "date-fns";

interface NewsItem {
  id: string;
  content: string;
  priority: "normal" | "high";
  branch_location: string;
  is_active: boolean;
  expires_at: string | null;
  created_at: string;
}

export function NewsTickerBar() {
  const [newsItems, setNewsItems] = useState<NewsItem[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const { activeBranch } = useBranch();

  useEffect(() => {
    fetchActiveNews();

    // Subscribe to real-time updates
    const channel = supabase
      .channel("news_ticker_updates")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "news_ticker",
        },
        () => {
          fetchActiveNews();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [activeBranch]);

  const fetchActiveNews = async () => {
    try {
      const now = new Date().toISOString();
      const currentBranch =
        typeof activeBranch === "string"
          ? activeBranch
          : (activeBranch as any)?.name || "calicut";

      const { data, error } = await supabase
        .from("news_ticker" as any)
        .select("*")
        .eq("is_active", true)
        .or(`expires_at.is.null,expires_at.gt.${now}`)
        .order("priority", { ascending: false })
        .order("created_at", { ascending: false });

      if (error) throw error;

      // Filter by branch
      const filteredNews = ((data as any) || []).filter(
        (item: any) =>
          item.branch_location === currentBranch ||
          item.branch_location === "global"
      );

      setNewsItems(filteredNews as NewsItem[]);
    } catch (error) {
      console.error("Error fetching news:", error);
    }
  };

  const isNew = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffInHours = (now.getTime() - date.getTime()) / (1000 * 60 * 60);
    return diffInHours < 24;
  };

  if (newsItems.length === 0) {
    return null;
  }

  return (
    <div className="w-full mb-8 px-1">
      <div className="relative overflow-hidden rounded-2xl bg-[#e0e5ec] shadow-[9px_9px_16px_rgba(163,177,198,0.6),-9px_-9px_16px_rgba(255,255,255,0.8)] border border-white/20">
        <div className="flex items-stretch h-14">
          {/* Live Badge Section - Gold/Yellow Theme */}
          <div className="relative z-10 flex items-center px-6 bg-gradient-to-r from-[#FFD700] via-[#FDB931] to-[#FFD700] shadow-[4px_0_15px_rgba(255,215,0,0.3)]">
            <div className="flex items-center gap-3">
              <div className="relative flex items-center justify-center w-8 h-8">
                <div className="absolute inset-0 bg-yellow-100 rounded-full animate-ping opacity-75"></div>
                <div className="relative z-10 bg-white/20 backdrop-blur-sm rounded-full p-1.5 shadow-inner border border-white/40">
                  <Zap
                    className="w-full h-full text-yellow-900 fill-yellow-900"
                    strokeWidth={2.5}
                  />
                </div>
              </div>
              <span className="text-yellow-950 font-black text-sm tracking-[0.2em] uppercase hidden sm:block drop-shadow-sm">
                FETS LIVE
              </span>
            </div>
            {/* Angled Divider */}
            <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-r from-transparent to-[#e0e5ec] translate-x-4 skew-x-12 opacity-90 blur-sm"></div>
          </div>

          {/* Ticker Content - Neumorphic Inset */}
          <div
            className="flex-1 flex items-center overflow-hidden relative shadow-[inset_3px_3px_6px_#bec3c9,inset_-3px_-3px_6px_#ffffff] bg-[#e0e5ec]/50"
            onMouseEnter={() => setIsPaused(true)}
            onMouseLeave={() => setIsPaused(false)}
          >
            <motion.div
              className="flex gap-16 px-8 whitespace-nowrap"
              animate={{
                x: isPaused ? 0 : [0, -1000],
              }}
              transition={{
                x: {
                  repeat: Infinity,
                  repeatType: "loop",
                  duration: Math.max(30, newsItems.length * 15), // Smoother scrolling
                  ease: "linear",
                },
              }}
            >
              {[...newsItems, ...newsItems, ...newsItems].map((item, index) => (
                <div
                  key={`${item.id}-${index}`}
                  className="inline-flex items-center gap-4 group"
                >
                  {/* Priority Indicator - Neumorphic Pill */}
                  {item.priority === "high" ? (
                    <span className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-[#e0e5ec] shadow-[3px_3px_6px_#bec3c9,-3px_-3px_6px_#ffffff] border border-red-200/30 text-red-600 text-[10px] font-bold uppercase tracking-wider">
                      <AlertTriangle size={12} className="fill-red-600/20" />
                      Urgent
                    </span>
                  ) : isNew(item.created_at) ? (
                    <span className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-[#e0e5ec] shadow-[3px_3px_6px_#bec3c9,-3px_-3px_6px_#ffffff] border border-blue-200/30 text-blue-600 text-[10px] font-bold uppercase tracking-wider">
                      <Clock size={12} className="fill-blue-600/20" />
                      New
                    </span>
                  ) : (
                    <span className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-[#e0e5ec] shadow-[3px_3px_6px_#bec3c9,-3px_-3px_6px_#ffffff] border border-gray-200/30 text-gray-500 text-[10px] font-bold uppercase tracking-wider">
                      <Info size={12} />
                      Info
                    </span>
                  )}

                  {/* Content */}
                  <span className="text-gray-700 font-medium text-sm tracking-wide group-hover:text-amber-900 transition-colors cursor-pointer select-none">
                    {item.content}
                  </span>

                  {/* Separator - Small golden dot */}
                  <div className="w-1.5 h-1.5 rounded-full bg-yellow-500/30 shadow-[1px_1px_2px_rgba(0,0,0,0.1)]" />
                </div>
              ))}
            </motion.div>

            {/* Fade Gradients */}
            <div className="absolute left-0 top-0 bottom-0 w-16 bg-gradient-to-r from-[#e0e5ec] via-[#e0e5ec]/80 to-transparent z-10" />
            <div className="absolute right-0 top-0 bottom-0 w-16 bg-gradient-to-l from-[#e0e5ec] via-[#e0e5ec]/80 to-transparent z-10" />
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Search,
  Filter,
  Plus,
  AlertTriangle,
  Phone,
  Copy,
  ExternalLink,
  FolderLock,
  Pin,
  Share2,
  BookOpen,
  FileText,
  Zap,
  Clock,
  Tag,
  Star,
  X,
  ChevronRight,
  Download,
  Eye,
  Edit,
  Trash2,
  Bookmark,
  Shield,
  Wifi,
  Database,
  Settings,
  Users,
  Activity,
  Layers,
  CheckCircle,
  TrendingUp,
} from "lucide-react";
import { useAuth } from "../hooks/useAuth";
import { supabase } from "../lib/supabase";
import { toast } from "react-hot-toast";

interface VaultCategory {
  id: string;
  name: string;
  icon: string;
  color: string;
  description?: string;
  display_order: number;
}

interface VaultItem {
  id: string;
  title: string;
  description: string;
  content: string;
  category: string;
  type: string;
  file_url: string;
  priority: string;
  tags: string[];
  is_confidential: boolean;
  is_deleted: boolean;
  category_id: string;
  author_id: string;
  created_at: string;
  updated_at: string;
}

interface ItemPin {
  id: string;
  item_id: string;
  user_id: string;
  created_at: string;
}

const PRIORITY_CONFIG = {
  high: {
    color: "bg-red-50 text-red-700 border-red-200",
    dot: "bg-red-500",
    label: "High Priority",
    gradient: "from-red-500 to-red-600",
  },
  normal: {
    color: "bg-blue-50 text-blue-700 border-blue-200",
    dot: "bg-blue-500",
    label: "Normal",
    gradient: "from-blue-500 to-blue-600",
  },
  low: {
    color: "bg-gray-50 text-gray-700 border-gray-200",
    dot: "bg-gray-500",
    label: "Low Priority",
    gradient: "from-gray-500 to-gray-600",
  },
};

const TYPE_CONFIG = {
  sop: {
    icon: BookOpen,
    color: "bg-purple-500",
    label: "SOP",
    gradient: "from-purple-500 to-purple-600",
  },
  contact: {
    icon: Phone,
    color: "bg-green-500",
    label: "Contact",
    gradient: "from-green-500 to-green-600",
  },
  document: {
    icon: FileText,
    color: "bg-blue-500",
    label: "Document",
    gradient: "from-blue-500 to-blue-600",
  },
  procedure: {
    icon: Settings,
    color: "bg-orange-500",
    label: "Procedure",
    gradient: "from-orange-500 to-orange-600",
  },
  emergency: {
    icon: AlertTriangle,
    color: "bg-red-500",
    label: "Emergency",
    gradient: "from-red-500 to-red-600",
  },
};

export default function ResourceCentre() {
  const { profile, hasPermission } = useAuth();

  const [categories, setCategories] = useState<VaultCategory[]>([]);
  const [items, setItems] = useState<VaultItem[]>([]);
  const [pins, setPins] = useState<ItemPin[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedItem, setSelectedItem] = useState<VaultItem | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [loading, setLoading] = useState(true);
  const [userRole, setUserRole] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);

  // Add Resource Form State
  const [newResource, setNewResource] = useState({
    title: "",
    description: "",
    content: "",
    type: "document",
    priority: "normal",
    category_id: "",
    file_url: "",
    is_confidential: false,
  });

  // Edit Resource State
  const [editResource, setEditResource] = useState<VaultItem | null>(null);

  // Category Management State
  const [categoryForm, setCategoryForm] = useState({
    id: "",
    name: "",
    icon: "",
    color: "#3B82F6",
    description: "",
  });

  const loadCategories = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from("vault_categories")
        .select("*")
        .order("display_order", { ascending: true });

      if (error) throw error;
      setCategories(data || []);
    } catch (error) {
      console.error("Error loading categories:", error);
      toast.error("Failed to load categories");
    }
  }, []);

  const loadItems = useCallback(async () => {
    try {
      if (!profile) return;

      const { data: userProfile, error: profileError } = await supabase
        .from("staff_profiles")
        .select("role")
        .eq("user_id", profile.user_id)
        .single();

      if (profileError) {
        console.error("Profile error:", profileError);
      }
      setUserRole(userProfile?.role || null);

      let query = supabase
        .from("fets_vault")
        .select("*")
        .eq("is_deleted", false)
        .order("priority", { ascending: false })
        .order("updated_at", { ascending: false });

      if (selectedCategory) {
        query = query.eq("category_id", selectedCategory);
      }

      if (searchQuery) {
        query = query.or(
          `title.ilike.%${searchQuery}%,description.ilike.%${searchQuery}%,content.ilike.%${searchQuery}%`
        );
      }

      const { data, error } = await query;
      if (error) {
        throw new Error(`Failed to load resources: ${error.message}`);
      }

      setItems(data || []);
    } catch (error: any) {
      console.error("Error loading items:", error);
      toast.error(error?.message || "Failed to load resources");
    }
  }, [profile, selectedCategory, searchQuery]);

  const loadPins = useCallback(async () => {
    if (!profile?.id) return;

    try {
      const { data, error } = await supabase
        .from("vault_item_pins")
        .select("*")
        .eq("user_id", profile.id);

      if (error) {
        throw new Error(`Failed to load pins: ${error.message}`);
      }
      setPins(data || []);
    } catch (error: any) {
      console.error("Error loading pins:", error);
    }
  }, [profile]);

  // Load all data
  const loadAllData = useCallback(async () => {
    setLoading(true);
    try {
      await Promise.all([loadCategories(), loadPins()]);
      await loadItems();
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setLoading(false);
    }
  }, [loadCategories, loadPins, loadItems]);

  useEffect(() => {
    loadAllData();
  }, [selectedCategory, searchQuery]);

  const pinnedItems = useMemo(() => {
    const pinnedIds = pins.map((p) => p.item_id);
    return items.filter((item) => pinnedIds.includes(item.id));
  }, [items, pins]);

  const togglePin = async (itemId: string) => {
    if (!profile?.id) return;

    try {
      const existingPin = pins.find((p) => p.item_id === itemId);

      if (existingPin) {
        await supabase
          .from("vault_item_pins")
          .delete()
          .eq("id", existingPin.id);
        setPins(pins.filter((p) => p.id !== existingPin.id));
        toast.success("Unpinned from Quick Access");
      } else {
        const { data, error } = await supabase
          .from("vault_item_pins")
          .insert({ item_id: itemId, user_id: profile.id })
          .select()
          .single();

        if (error) throw error;
        setPins([...pins, data]);
        toast.success("Pinned to Quick Access");
      }
    } catch (error) {
      console.error("Error toggling pin:", error);
      toast.error("Failed to update pin");
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success("Copied to clipboard!");
  };

  const viewDetails = (item: VaultItem) => {
    setSelectedItem(item);
    setShowDetailModal(true);
  };

  const createResource = async () => {
    if (!profile?.id) {
      toast.error("You must be logged in to create a resource");
      return;
    }

    if (!newResource.title.trim()) {
      toast.error("Title is required");
      return;
    }

    if (!newResource.content.trim()) {
      toast.error("Content is required");
      return;
    }

    setSubmitting(true);
    try {
      const { error } = await supabase
        .from("fets_vault")
        .insert({
          title: newResource.title,
          description: newResource.description,
          content: newResource.content,
          type: newResource.type,
          priority: newResource.priority,
          category_id: newResource.category_id || categories[0]?.id,
          file_url: newResource.file_url,
          tags: [],
          is_confidential: newResource.is_confidential,
          author_id: profile.id,
          category:
            categories.find((c) => c.id === newResource.category_id)?.name ||
            "General",
        })
        .select()
        .single();

      if (error) throw error;

      toast.success("Resource created successfully!");
      setShowAddModal(false);
      setNewResource({
        title: "",
        description: "",
        content: "",
        type: "document",
        priority: "normal",
        category_id: "",
        file_url: "",
        is_confidential: false,
      });
      loadAllData();
    } catch (error: any) {
      console.error("Error creating resource:", error);
      toast.error(error?.message || "Failed to create resource");
    } finally {
      setSubmitting(false);
    }
  };

  const updateResource = async () => {
    if (!editResource || !profile?.id) return;

    setSubmitting(true);
    try {
      const { error } = await supabase
        .from("fets_vault")
        .update({
          title: editResource.title,
          description: editResource.description,
          content: editResource.content,
          type: editResource.type,
          priority: editResource.priority,
          category_id: editResource.category_id,
          file_url: editResource.file_url,
          is_confidential: editResource.is_confidential,
          updated_at: new Date().toISOString(),
        })
        .eq("id", editResource.id);

      if (error) throw error;

      toast.success("Resource updated successfully!");
      setShowEditModal(false);
      setEditResource(null);
      loadAllData();
    } catch (error: any) {
      console.error("Error updating resource:", error);
      toast.error(error?.message || "Failed to update resource");
    } finally {
      setSubmitting(false);
    }
  };

  const deleteResource = async (resourceId: string) => {
    if (
      !window.confirm(
        "Are you sure you want to delete this resource? This action cannot be undone."
      )
    )
      return;

    try {
      const { error } = await supabase
        .from("fets_vault")
        .update({
          is_deleted: true,
          updated_at: new Date().toISOString(),
        })
        .eq("id", resourceId);

      if (error) throw error;

      toast.success("Resource deleted successfully!");
      setShowDetailModal(false);
      setShowEditModal(false);
      loadAllData();
    } catch (error: any) {
      console.error("Error deleting resource:", error);
      toast.error(
        `Failed to delete resource: ${error.message || "Unknown error"}`
      );
    }
  };

  const saveCategory = async () => {
    if (!categoryForm.name.trim()) {
      toast.error("Category name is required");
      return;
    }

    setSubmitting(true);
    try {
      if (categoryForm.id) {
        const { error } = await supabase
          .from("vault_categories")
          .update({
            name: categoryForm.name,
            icon: categoryForm.icon,
            color: categoryForm.color,
            description: categoryForm.description,
          })
          .eq("id", categoryForm.id);

        if (error) throw error;
        toast.success("Category updated successfully!");
      } else {
        const { error } = await supabase.from("vault_categories").insert({
          name: categoryForm.name,
          icon: categoryForm.icon,
          color: categoryForm.color,
          description: categoryForm.description,
          display_order: categories.length,
          created_by: profile?.id,
        });

        if (error) throw error;
        toast.success("Category created successfully!");
      }

      setShowCategoryModal(false);
      setCategoryForm({
        id: "",
        name: "",
        icon: "",
        color: "#3B82F6",
        description: "",
      });
      loadCategories();
    } catch (error: any) {
      console.error("Error saving category:", error);
      toast.error(error?.message || "Failed to save category");
    } finally {
      setSubmitting(false);
    }
  };

  const deleteCategory = async (categoryId: string) => {
    if (
      !window.confirm(
        "Are you sure you want to delete this category? Resources in this category will not be affected."
      )
    )
      return;

    try {
      const { error } = await supabase
        .from("vault_categories")
        .delete()
        .eq("id", categoryId);

      if (error) throw error;

      toast.success("Category deleted successfully!");
      setShowCategoryModal(false);
      loadCategories();
    } catch (error: any) {
      console.error("Error deleting category:", error);
      toast.error(error?.message || "Failed to delete category");
    }
  };

  const handleEditResource = (item: VaultItem) => {
    setEditResource({ ...item });
    setShowEditModal(true);
  };

  const isAdmin = hasPermission("sop_edit");

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-4xl md:text-5xl font-bold tracking-tight mb-2 uppercase text-gold-gradient">
            Resource Centre
          </h1>
          <p className="text-gray-500 mt-1">
            Central repository for training, SOPs, and credentials.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search resources..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 w-full md:w-64 transition-all shadow-sm"
            />
          </div>
          {isAdmin && (
            <button
              onClick={() => setShowAddModal(true)}
              className="p-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm"
              title="Add New Resource"
            >
              <Plus className="w-5 h-5" />
            </button>
          )}
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Sidebar Categories */}
        <div className="w-full lg:w-64 flex-shrink-0 space-y-1">
          <button
            onClick={() => setSelectedCategory(null)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${
              selectedCategory === null
                ? "bg-white text-indigo-600 shadow-sm ring-1 ring-gray-200"
                : "text-gray-600 hover:bg-gray-100"
            }`}
          >
            <Layers className="w-4 h-4" />
            All Resources
          </button>
          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => setSelectedCategory(cat.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${
                selectedCategory === cat.id
                  ? "bg-white text-indigo-600 shadow-sm ring-1 ring-gray-200"
                  : "text-gray-600 hover:bg-gray-100"
              }`}
            >
              <FolderLock className="w-4 h-4" />
              {cat.name}
            </button>
          ))}

          {isAdmin && (
            <button
              onClick={() => setShowCategoryModal(true)}
              className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium text-gray-400 hover:text-gray-600 hover:bg-gray-50 mt-4 border-t border-gray-100 transition-colors"
            >
              <Settings className="w-4 h-4" />
              Manage Categories
            </button>
          )}
        </div>

        {/* Main Content */}
        <div className="flex-1 min-w-0">
          {/* Quick Access Section */}
          {pinnedItems.length > 0 && !searchQuery && !selectedCategory && (
            <div className="mb-8">
              <h2 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                <Pin className="w-3 h-3" /> Quick Access
              </h2>
              <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-4">
                {pinnedItems.map((item) => {
                  const typeConfig =
                    TYPE_CONFIG[item.type as keyof typeof TYPE_CONFIG] ||
                    TYPE_CONFIG.document;
                  const TypeIcon = typeConfig.icon;
                  const colorClass = typeConfig.color.split("-")[1]; // e.g., 'purple' from 'bg-purple-500'

                  return (
                    <div
                      key={item.id}
                      onClick={() => viewDetails(item)}
                      className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all cursor-pointer group relative"
                    >
                      <div className="flex items-start justify-between mb-2">
                        <div
                          className={`p-2 rounded-lg ${typeConfig.color} bg-opacity-10 text-${colorClass}-600`}
                        >
                          <TypeIcon size={18} />
                        </div>
                        <Pin className="w-4 h-4 text-amber-400 fill-amber-400" />
                      </div>
                      <h3 className="font-semibold text-gray-900 truncate pr-6">
                        {item.title}
                      </h3>
                      <p className="text-xs text-gray-500 mt-1 line-clamp-1">
                        {item.description}
                      </p>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Resources List */}
          <div>
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-bold text-gray-900">
                {selectedCategory
                  ? categories.find((c) => c.id === selectedCategory)?.name
                  : "Library"}
              </h2>
              <span className="text-sm text-gray-500">
                {items.length} items
              </span>
            </div>

            {items.length === 0 ? (
              <div className="text-center py-16 bg-white rounded-xl border border-gray-200 border-dashed">
                <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-3">
                  <Search className="w-5 h-5 text-gray-400" />
                </div>
                <p className="text-gray-900 font-medium">No resources found</p>
                <p className="text-sm text-gray-500 mt-1">
                  {searchQuery
                    ? "Try adjusting your search terms"
                    : "Select a different category or add a new resource"}
                </p>
              </div>
            ) : (
              <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                <div className="divide-y divide-gray-100">
                  {items.map((item) => {
                    const typeConfig =
                      TYPE_CONFIG[item.type as keyof typeof TYPE_CONFIG] ||
                      TYPE_CONFIG.document;
                    const TypeIcon = typeConfig.icon;
                    const colorClass = typeConfig.color.split("-")[1];
                    const isPinned = pins.some((p) => p.item_id === item.id);

                    return (
                      <div
                        key={item.id}
                        onClick={() => viewDetails(item)}
                        className="p-4 hover:bg-gray-50 transition-colors cursor-pointer flex items-center gap-4 group"
                      >
                        <div
                          className={`flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center ${typeConfig.color} bg-opacity-10`}
                        >
                          <TypeIcon
                            size={20}
                            className={`text-${colorClass}-600`}
                          />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <h3 className="font-medium text-gray-900 truncate">
                              {item.title}
                            </h3>
                            {item.is_confidential && (
                              <div
                                className="flex-shrink-0"
                                title="Confidential"
                              >
                                <Shield className="w-3 h-3 text-red-500" />
                              </div>
                            )}
                            {item.priority === "high" && (
                              <span className="px-1.5 py-0.5 bg-red-100 text-red-700 text-[10px] font-bold uppercase rounded">
                                High
                              </span>
                            )}
                          </div>
                          <p className="text-sm text-gray-500 truncate">
                            {item.description}
                          </p>
                        </div>
                        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              togglePin(item.id);
                            }}
                            className={`p-2 rounded-full hover:bg-gray-200 transition-colors ${
                              isPinned ? "text-amber-500" : "text-gray-400"
                            }`}
                            title={isPinned ? "Unpin" : "Pin to Quick Access"}
                          >
                            <Pin
                              className={`w-4 h-4 ${
                                isPinned ? "fill-amber-500" : ""
                              }`}
                            />
                          </button>
                          <ChevronRight className="w-4 h-4 text-gray-300" />
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Add Resource Modal */}
      {showAddModal && (
        <ResourceFormModal
          title="Add New Resource"
          categories={categories}
          resource={newResource}
          setResource={setNewResource}
          onSave={createResource}
          onClose={() => {
            setShowAddModal(false);
            setNewResource({
              title: "",
              description: "",
              content: "",
              type: "document",
              priority: "normal",
              category_id: "",
              file_url: "",
              is_confidential: false,
            });
          }}
          submitting={submitting}
        />
      )}

      {/* Edit Resource Modal */}
      {showEditModal && editResource && (
        <ResourceFormModal
          title="Edit Resource"
          categories={categories}
          resource={editResource}
          setResource={setEditResource}
          onSave={updateResource}
          onClose={() => {
            setShowEditModal(false);
            setEditResource(null);
          }}
          submitting={submitting}
          onDelete={() => deleteResource(editResource.id)}
        />
      )}

      {/* Detail Modal */}
      {showDetailModal && selectedItem && (
        <ResourceDetailModal
          item={selectedItem}
          onClose={() => {
            setShowDetailModal(false);
            setSelectedItem(null);
          }}
          onEdit={() => {
            setShowDetailModal(false);
            handleEditResource(selectedItem);
          }}
          onPin={() => togglePin(selectedItem.id)}
          isPinned={pins.some((p) => p.item_id === selectedItem.id)}
          copyToClipboard={copyToClipboard}
          typeConfig={
            TYPE_CONFIG[selectedItem.type as keyof typeof TYPE_CONFIG] ||
            TYPE_CONFIG.document
          }
          priorityConfig={
            PRIORITY_CONFIG[
              selectedItem.priority as keyof typeof PRIORITY_CONFIG
            ] || PRIORITY_CONFIG.normal
          }
          isAdmin={isAdmin}
        />
      )}
      {/* Category Modal */}
      {showCategoryModal && (
        <CategoryFormModal
          category={categoryForm}
          setCategory={setCategoryForm}
          onSave={saveCategory}
          onClose={() => setShowCategoryModal(false)}
          submitting={submitting}
          onDelete={
            categoryForm.id ? () => deleteCategory(categoryForm.id) : undefined
          }
        />
      )}
    </div>
  );
}

