                </p>
                <div className="h-2 w-full bg-white/10 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-amber-500 transition-all duration-1000"
                    style={{
                      width:
                        metrics.total > 0
                          ? `${
                              (metrics.positives /
                                (metrics.positives + metrics.totalIssues)) *
                              100
                            }%`
                          : "0%",
                    }}
                  />
