import React, { useState, useMemo, useEffect } from "react";
import { useForm } from "react-hook-form";
import {
  X,
  Save,
  ClipboardCheck,
  AlertCircle,
  CheckCircle2,
  Paperclip,
  FileText,
  LayoutList,
  ChevronRight,
  Check,
  Shield,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { ChecklistTemplate } from "../../types/checklist";
import { supabase } from "../../lib/supabase";
import toast from "react-hot-toast";
import FileUpload from "../FileUpload";

interface ChecklistFormModalProps {
  template: ChecklistTemplate;
  onClose: () => void;
  onSuccess?: () => void;
  currentUser: any;
  overrideStaff?: { id: string; name: string };
  overrideBranch?: string;
}

export const ChecklistFormModal: React.FC<ChecklistFormModalProps> = ({
  template,
  onClose,
  onSuccess,
  currentUser,
  overrideStaff,
  overrideBranch,
}) => {
  const {
    register,
    handleSubmit,
    formState: { errors },
    watch,
    setValue,
  } = useForm();
  const [submitting, setSubmitting] = useState(false);
  const [attachments, setAttachments] = useState<Record<string, any[]>>({});
  const [activeSection, setActiveSection] = useState<string>("");
  const [availableSystems, setAvailableSystems] = useState<any[]>([]); // Systems for dropdown

  useEffect(() => {
    const fetchSystems = async () => {
      const { data } = await supabase
        .from("systems")
        .select("id, name, branch_location, system_type, ip_address")
        .order("name");
      if (data) setAvailableSystems(data);
    };
    fetchSystems();
  }, []);

  const questions = template.questions || [];
  const watchedValues = watch();

  // Theme Configuration based on checklist type
  const theme = useMemo(() => {
    const isPre = template.type === "pre_exam";
    const isPost = template.type === "post_exam";

    if (isPre)
      return {
        primary: "bg-[#AEEC27]", // Lime Green
        secondary: "bg-[#AEEC27]/10",
        text: "text-[#AEEC27]",
        border: "border-[#AEEC27]/30",
        accent: "#AEEC27",
        shadow: "shadow-[0_0_15px_rgba(174,236,39,0.3)]",
      };
    if (isPost)
      return {
        primary: "bg-[#C0F050]", // Slightly lighter lime green variation
        secondary: "bg-[#C0F050]/10",
        text: "text-[#C0F050]",
        border: "border-[#C0F050]/30",
        accent: "#C0F050",
        shadow: "shadow-[0_0_15px_rgba(192,240,80,0.3)]",
      };
    return {
      primary: "bg-[#AEEC27]",
      secondary: "bg-[#15171C]",
      text: "text-[#AEEC27]",
      border: "border-[#353A47]",
      accent: "#AEEC27",
      shadow: "shadow-[0_0_15px_rgba(174,236,39,0.3)]",
    };
  }, [template.type]);

  // Group questions by section
  const sectionedQuestions = useMemo(() => {
    const groups: Record<string, any[]> = {};
    questions.forEach((q) => {
      const section = q.section || "General Checks";
      if (!groups[section]) groups[section] = [];
      groups[section].push(q);
    });
    return groups;
  }, [questions]);

  const sections = useMemo(
    () => Object.keys(sectionedQuestions),
    [sectionedQuestions]
  );

  useEffect(() => {
    if (sections.length > 0 && !activeSection) {
      setActiveSection(sections[0]);
    }
  }, [sections]);

  // Progress Calculation
  const progress = useMemo(() => {
    const total = questions.length;
    if (total === 0) return 0;
    const filled = questions.filter((q) => {
      const val = watchedValues[q.id];
      if (q.type === "checkbox") return val === true;
      return val !== undefined && val !== "";
    }).length;
    return Math.round((filled / total) * 100);
  }, [questions, watchedValues]);

  const onSubmit = async (data: any) => {
    const missingAttachments = questions.filter(
      (q) =>
        q.attachment_mode === "required" &&
        (!attachments[q.id] || attachments[q.id].length === 0)
    );
    if (missingAttachments.length > 0) {
      toast.error(`Photo is required for: ${missingAttachments[0].text}`);
      return;
    }

    setSubmitting(true);
    try {
      // 1. Verify session explicitly to catch 'Invalid Refresh Token'
      const { data: sessionData, error: sessionError } =
        await supabase.auth.getSession();
      if (sessionError || !sessionData.session) {
        toast.error(
          "Your session has expired. Please refresh the page and log in again."
        );
        setSubmitting(false);
        return;
      }

      // 2. Ensure currentUser profile is loaded
      if (!currentUser) {
        toast.error("User profile not fully loaded. Please refresh the page.");
        setSubmitting(false);
        return;
      }

      // CRITICAL: submitted_by MUST be the auth.uid() (user_id from staff_profiles)
      // The RLS policy requires auth.uid() = submitted_by for INSERT
      // Note: When overrideStaff is used for admin submission on behalf of another user,
      // we still use the current user's auth ID since that's what RLS checks
      const authUserId = currentUser?.user_id || currentUser?.id;

      if (!authUserId) {
        toast.error(
          "Session error: Could not verify user identity. Please log in again."
        );
        setSubmitting(false);
        return;
      }

      const submission = {
        template_id: template.id,
        submitted_by: authUserId, // Always use the authenticated user's ID
        branch_id:
          overrideBranch ||
          currentUser.branch_assigned ||
          currentUser.branch_id ||
          null,
        submitted_at: new Date().toISOString(),
        answers: data,
        attachments: attachments,
        status: "submitted",
      };

      console.log("≡ƒôï Submitting checklist:", {
        template_id: submission.template_id,
        submitted_by: submission.submitted_by,
        branch_id: submission.branch_id,
        currentUser_user_id: currentUser?.user_id,
        currentUser_id: currentUser?.id,
      });

      const { error } = await supabase
        .from("checklist_submissions")
        .insert(submission);
      if (error) {
        console.error("Γ¥î Supabase insert error:", error);
        throw error;
      }

      console.log("Γ£à Checklist submitted successfully");
      toast.success("Form saved successfully.");
      if (onSuccess) onSuccess();
      onClose();
    } catch (error: any) {
      console.error("Γ¥î Submission error:", error);
      toast.error(error.message || "Failed to save form.");
    } finally {
      setSubmitting(false);
    }
  };

  const handleFilesSelected = (questionId: string, files: any[]) => {
    setAttachments((prev) => ({ ...prev, [questionId]: files }));
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.05 },
