  const itemVariants = {
    hidden: { opacity: 0, y: 10 },
    visible: { opacity: 1, y: 0 },
  };

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-0 md:p-6 bg-[#0D0E11]/80 backdrop-blur-md">
      <motion.div
        initial={{ opacity: 0, scale: 0.9, y: 40 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.9, y: 40 }}
        className="w-full max-w-6xl h-full md:h-[90vh] flex flex-col bg-[#0D0E11] md:rounded-[3rem] shadow-[0_0_40px_rgba(0,0,0,0.5)] overflow-hidden border border-[#353A47]"
      >
