          <div className="absolute bottom-0 left-0 w-full h-1 bg-[#1A1D24] opacity-50">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${progress}%` }}
              className={`h-full ${theme.primary} transition-all duration-700 shadow-[0_0_10px_currentColor]`}
            />
          </div>

          <div className="flex items-center justify-between relative z-10">
            <div className="flex items-center gap-4 md:gap-8">
              <div
                className={`w-14 h-14 md:w-16 md:h-16 rounded-2xl ${theme.primary} flex items-center justify-center text-[#0D0E11] shadow-xl ${theme.shadow} rotate-[-2deg] transition-all`}
              >
                <ClipboardCheck size={32} className="md:size-8" />
              </div>
              <div>
                <h2 className="text-2xl md:text-3xl font-black text-[#FDFFF8] tracking-tight leading-tight mb-1 select-none heading-outfit">
                  {template.title}
                </h2>
                <div className="flex flex-wrap items-center gap-2 md:gap-4">
                  <span
                    className={`px-2.5 py-0.5 ${theme.secondary} ${theme.text} text-[10px] font-black uppercase tracking-[0.1em] rounded-md border ${theme.border}`}
                  >
                    Active Form
                  </span>
                  <div className="hidden md:block w-1 h-1 rounded-full bg-[#353A47]" />
                  <p className="text-[#A0A5B5] text-[10px] md:text-xs font-bold truncate max-w-[200px] md:max-w-none">
                    {template.description || "Daily verification check"}
                  </p>
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex flex-col items-end mr-4">
                <span className="text-[10px] font-black text-[#6B7280] uppercase tracking-widest mb-1">
                  Items Filled
                </span>
                <span
                  className={`text-xl font-black ${theme.text} leading-none heading-outfit`}
                >
                  {progress}%
                </span>
              </div>
              <button
                onClick={onClose}
                className="p-3 md:p-4 rounded-2xl bg-[#1A1D24] border border-[#353A47] text-[#6B7280] hover:text-[#EF4444] hover:bg-[#EF4444]/10 hover:border-[#EF4444]/30 transition-all active:scale-95 group"
              >
                <X
                  size={20}
                  className="group-hover:rotate-90 transition-transform"
                />
              </button>
            </div>
          </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* Left Sidebar Navigation (Desktop) */}
          <div className="hidden lg:flex w-64 flex-col bg-[#0D0E11] border-r border-[#353A47] p-6 overflow-y-auto custom-scrollbar">
            <span className="text-[10px] font-black text-[#6B7280] uppercase tracking-[0.2em] mb-6 px-2">
              Checklist Steps
            </span>
            <div className="space-y-2">
              {sections.map((section, idx) => {
                const isCompleted = sectionedQuestions[section].every((q) => {
                  const val = watchedValues[q.id];
                  if (q.type === "checkbox") return val === true;
                  return val !== undefined && val !== "";
                });
                const isActive = activeSection === section;

                return (
                  <button
                    key={section}
                    onClick={() => {
                      setActiveSection(section);
                      document
