                    className={`w-full p-4 rounded-2xl flex items-center gap-3 transition-all text-left ${
                      isActive
                        ? `${theme.primary} text-[#0D0E11] shadow-lg ${theme.shadow}`
                        : "hover:bg-[#1A1D24] text-[#A0A5B5] hover:text-[#FDFFF8]"
                    }`}
                  >
                    <div
                      className={`w-7 h-7 rounded-lg flex items-center justify-center text-[10px] font-black shrink-0 ${
                        isActive
