                        // ---------------------------------------------------------
                        // LOGIC: Conditional Visibility & Custom System Error Input
                        // ---------------------------------------------------------

                        // 1. Identify if this is the dependent question
                        const isSystemErrorQuestion =
                          q.text.toLowerCase().includes("system number") &&
                          q.text.toLowerCase().includes("error note");

                        // 2. Conditional Visibility Logic
                        if (isSystemErrorQuestion) {
                          const triggerQuestion = questions.find((qst) =>
                            qst.text
                              .toLowerCase()
                              .includes("any workstation errors")
                          );
                          // If trigger exists, check its value. If it's NOT "Yes" (or equivalent positive), hide this question.
                          if (triggerQuestion) {
                            const triggerValue =
                              watchedValues[triggerQuestion.id];
                            const isYes =
                              typeof triggerValue === "string" &&
                              ["yes", "fail", "error", "issues"].some((v) =>
                                triggerValue.toLowerCase().includes(v)
                              );
                            // Also check for boolean true if it's a checkbox, though usually these are Radios
                            const isChecked = triggerValue === true;

                            if (!isYes && !isChecked) return null;
                          }
                        }

                        // 3. Render Custom System Selector if matched
                        if (isSystemErrorQuestion) {
                          return (
                            <SystemErrorInput
                              key={q.id}
                              question={q}
                              theme={theme}
                              register={register}
                              setValue={setValue}
                              watch={watch}
