                            key={q.id || idx}
                            variants={itemVariants}
                            className={`group p-6 md:p-8 rounded-[2rem] border transition-all duration-300 relative bg-[#15171C] ${
                              watchedValues[q.id]
                                ? "border-[#AEEC27] bg-[#1A1D24]"
                                : "border-[#353A47] hover:border-[#6B7280]"
