                                      placeholder="Type notes here..."
                                    />
                                  )}

                                  {q.type === "number" && (
                                    <div className="max-w-[150px]">
                                      <input
                                        type="number"
                                        step="any"
                                        {...register(q.id, {
                                          required: q.required,
                                        })}
                                        className={`w-full px-6 py-4 bg-[#1A1D24] border border-[#353A47] rounded-2xl focus:bg-[#2A2E39] focus:border-[${theme.accent}] outline-none transition-all text-[#FDFFF8] font-black text-xl shadow-inner`}
                                        placeholder="00"
                                      />
                                    </div>
                                  )}

                                  {q.type === "checkbox" && (
                                    <label
                                      className={`flex items-center gap-4 cursor-pointer p-5 rounded-2xl border-2 transition-all ${
                                        watchedValues[q.id]
                                          ? `border-[#AEEC27] bg-[#AEEC27]/5`
                                          : "border-[#1A1D24] hover:border-[#353A47] bg-[#1A1D24]"
                                      }`}
                                    >
                                      <div
                                        className={`w-7 h-7 rounded-lg border flex items-center justify-center transition-all ${
                                          watchedValues[q.id]
                                            ? "bg-[#AEEC27] border-[#AEEC27] text-[#0D0E11] shadow-[0_0_10px_rgba(174,236,39,0.3)]"
                                            : "bg-[#15171C] border-[#353A47]"
                                        }`}
                                      >
                                        <Check
                                          size={16}
                                          strokeWidth={3}
                                          className={
