                                        />
                                      </div>
                                      <input
                                        type="checkbox"
                                        {...register(q.id, {
                                          required: q.required,
                                        })}
                                        className="hidden"
                                      />
                                      <span
                                        className={`text-sm font-black uppercase tracking-widest ${
                                          watchedValues[q.id]
                                            ? "text-[#AEEC27]"
                                            : "text-[#A0A5B5]"
                                        }`}
                                      >
                                        I have checked this
