                                    </div>
                                  )}

                                  {q.type === "dropdown" && (
                                    <div className="relative">
                                      <select
                                        {...register(q.id, {
                                          required: q.required,
                                        })}
                                        className={`w-full px-6 py-4 bg-[#1A1D24] border border-[#353A47] rounded-2xl focus:bg-[#2A2E39] focus:border-[${theme.accent}] outline-none transition-all text-[#FDFFF8] font-bold appearance-none shadow-inner`}
                                      >
                                        <option value="">Choose one...</option>
