                                    />
                                  )}

                                  {q.type === "time" && (
                                    <input
                                      type="time"
                                      {...register(q.id, {
                                        required: q.required,
                                      })}
                                      className={`max-w-[200px] w-full px-6 py-4 bg-[#1A1D24] border border-[#353A47] rounded-2xl focus:bg-[#2A2E39] focus:border-[${theme.accent}] outline-none transition-all text-[#FDFFF8] font-black shadow-inner [color-scheme:dark]`}
                                    />
                                  )}

                                  {/* Evidence Upload Handler */}
                                  {q.attachment_mode &&
                                    q.attachment_mode !== "none" && (
                                      <div
                                        className={`mt-8 p-8 rounded-[2rem] border-2 border-dashed ${
                                          attachments[q.id]?.length > 0
                                            ? "border-[#AEEC27]/50 bg-[#AEEC27]/5"
                                            : "border-[#353A47] bg-[#1A1D24]"
                                        } hover:border-[#AEEC27]/50 transition-colors shadow-inner`}
                                      >
                                        <div className="flex items-center justify-between mb-6">
                                          <div className="flex items-center gap-3">
                                            <div
                                              className={`w-8 h-8 rounded-lg ${theme.primary} text-[#0D0E11] flex items-center justify-center shadow-[0_0_10px_rgba(174,236,39,0.3)]`}
                                            >
                                              <Paperclip size={16} />
                                            </div>
                                            <span className="text-[10px] font-black uppercase tracking-widest text-[#FDFFF8]">
                                              Attach Photo{" "}
                                              {q.attachment_mode === "required"
                                                ? "(Required)"
                                                : "(Optional)"}
                                            </span>
                                          </div>
                                          {attachments[q.id]?.length > 0 && (
                                            <div className="flex items-center gap-2 text-[#0D0E11] bg-[#AEEC27] px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-[0_0_10px_rgba(174,236,39,0.3)]">
                                              <Check
                                                size={14}
                                                strokeWidth={3}
                                              />{" "}
                                              Attached
                                            </div>
                                          )}
                                        </div>
                                        <FileUpload
                                          onFilesSelected={(files) =>
                                            handleFilesSelected(q.id, files)
                                          }
                                          maxFiles={1}
                                        />
                                      </div>
                                    )}
                                </div>

                                {/* Dynamic Error State */}
                                <AnimatePresence>
                                  {errors[q.id] && (
                                    <motion.div
                                      initial={{ opacity: 0, x: -10 }}
                                      animate={{ opacity: 1, x: 0 }}
                                      exit={{ opacity: 0, x: -10 }}
                                      className="flex items-center gap-2 text-[#EF4444] font-black text-[10px] uppercase tracking-widest px-1"
                                    >
                                      <AlertCircle size={14} /> Please fill this
                                      item
                                    </motion.div>
                                  )}
                                </AnimatePresence>
                              </div>
                            </div>
                          </motion.div>
                        );
                      })}
                    </div>
                  </motion.div>
                )
              )}
            </form>
          </div>
        </div>

        {/* Footer Dashboard Controls */}
        <div className="p-6 md:p-8 bg-[#15171C] border-t border-[#353A47] z-20">
          <div className="max-w-6xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6 md:gap-0">
            {/* Operator Display */}
            <div className="flex items-center gap-5">
              <div
                className={`w-14 h-14 md:w-16 md:h-16 rounded-2xl overflow-hidden border-2 border-[#353A47] shadow-lg`}
              >
                <img
                  src={
                    currentUser?.avatar_url ||
                    `https://ui-avatars.com/api/?name=${encodeURIComponent(
                      overrideStaff?.name || currentUser.full_name || "User"
                    )}&background=1A1D24&color=AEEC27&size=128`
                  }
                  alt="User"
                  className="w-full h-full object-cover"
                />
              </div>
              <div>
                <p className="text-[10px] font-black text-[#A0A5B5] uppercase tracking-widest mb-1 leading-none select-none">
                  Submitted by
                </p>
                <p className="text-[#FDFFF8] font-black text-lg tracking-tight leading-none heading-outfit">
                  {overrideStaff?.name ||
                    currentUser.full_name ||
                    currentUser.username}
                </p>
              </div>
            </div>

            {/* Submission Engine */}
            <div className="flex items-center gap-4 w-full md:w-auto">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 md:flex-none px-10 py-5 rounded-2xl font-black uppercase tracking-widest text-[11px] text-[#A0A5B5] hover:text-[#FDFFF8] hover:bg-[#1A1D24] transition-all active:scale-95 border border-transparent hover:border-[#353A47]"
              >
                Cancel
              </button>
              <button
                type="submit"
                form="checklist-form"
                disabled={submitting}
                className={`flex-1 md:flex-none px-14 py-5 rounded-[1.5rem] font-black uppercase tracking-[0.2em] text-[11px] ${theme.primary} text-[#0D0E11] shadow-[0_0_20px_rgba(174,236,39,0.2)] hover:shadow-[0_0_30px_rgba(174,236,39,0.4)] hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 disabled:hover:scale-100 disabled:shadow-none flex items-center justify-center gap-4 group/btn`}
              >
                {submitting ? (
                  <div className="w-5 h-5 border-2 border-[#0D0E11]/20 border-t-[#0D0E11] rounded-full animate-spin" />
                ) : (
                  <>
                    <Save size={18} />
                    <span>Save & Submit</span>
                    <ChevronRight
                      size={18}
                      className="hidden md:block group-hover/btn:translate-x-1 transition-transform"
                    />
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

const SystemErrorInput = ({
  question,
  theme,
  register,
  setValue,
  watch,
  errors,
  attachments,
  onFilesSelected,
  activeBranch,
  availableSystems,
}: any) => {
  const [selectedSysIds, setSelectedSysIds] = useState<string[]>([]);
  const [errorNote, setErrorNote] = useState("");
  const [search, setSearch] = useState("");

  // Initialize from form state if present
  useEffect(() => {
    const currentVal = watch(question.id);
    if (currentVal && typeof currentVal === "object") {
      if (currentVal.systems) setSelectedSysIds(currentVal.systems);
      if (currentVal.note) setErrorNote(currentVal.note);
    }
  }, [watch, question.id]);

  // Sync to form
  useEffect(() => {
    setValue(question.id, {
      systems: selectedSysIds,
      note: errorNote,
      summary: `${selectedSysIds.length} Systems: ${errorNote}`,
    });
  }, [selectedSysIds, errorNote, setValue, question.id]);

  const filteredSystems = availableSystems.filter((s: any) => {
    const matchesBranch =
      activeBranch === "Global" || s.branch_location === activeBranch;
    const matchesSearch =
      s.name.toLowerCase().includes(search.toLowerCase()) ||
      (s.ip_address && s.ip_address.includes(search));
    return matchesBranch && matchesSearch;
  });

  const toggleSystem = (id: string) => {
    setSelectedSysIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    );
  };

  return (
    <div
      className={`p-6 md:p-8 rounded-[2rem] border transition-all duration-300 bg-[#15171C] ${
        selectedSysIds.length > 0
          ? "border-[#C0F050] bg-[#1A1D24]"
          : "border-[#353A47]"
      }`}
    >
      <h3 className="text-lg md:text-xl font-black text-[#FDFFF8] leading-snug tracking-tight mb-4">
        {question.text} <span className="text-[#AEEC27] ml-1">*</span>
      </h3>

      <div className="space-y-6">
        {/* 1. System Selector */}
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-[#6B7280]">
            Affected System(s)
          </label>
          <div className="p-4 bg-[#1A1D24] rounded-2xl border border-[#353A47] shadow-inner">
            <input
              type="text"
              placeholder="Search systems..."
              className="w-full bg-transparent outline-none text-xs font-bold mb-4 border-b border-[#353A47] pb-2 text-[#FDFFF8] placeholder:text-[#6B7280]"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
            <div className="max-h-[150px] overflow-y-auto space-y-2 pr-2 custom-scrollbar">
              {filteredSystems.length > 0 ? (
                filteredSystems.map((sys: any) => (
                  <div
                    key={sys.id}
                    onClick={() => toggleSystem(sys.id)}
                    className={`flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                      selectedSysIds.includes(sys.id)
                        ? `bg-[${theme.accent}]/10 border-[${theme.accent}]/50 shadow-[0_0_10px_rgba(174,236,39,0.1)]`
                        : "bg-[#15171C] border-[#353A47] hover:border-[#6B7280]"
                    }`}
                  >
                    <div>
                      <p className="text-xs font-black uppercase text-[#FDFFF8]">
                        {sys.name}
                      </p>
                      <p className="text-[9px] font-bold text-[#A0A5B5]">
                        {sys.ip_address}
                      </p>
                    </div>
                    {selectedSysIds.includes(sys.id) && (
                      <div
                        className={`w-5 h-5 rounded-full ${theme.primary} text-[#0D0E11] flex items-center justify-center shadow-[0_0_10px_rgba(174,236,39,0.3)]`}
                      >
                        <Check size={12} strokeWidth={3} />
                      </div>
                    )}
                  </div>
                ))
              ) : (
                <p className="text-[10px] text-[#A0A5B5] italic">
                  No matching systems found in {activeBranch}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* 2. Error Note */}
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-[#6B7280]">
            Error Details
          </label>
          <textarea
            value={errorNote}
            onChange={(e) => setErrorNote(e.target.value)}
            className="w-full px-6 py-4 bg-[#1A1D24] border border-[#353A47] rounded-2xl focus:bg-[#2A2E39] focus:border-[${theme.accent}] outline-none transition-all text-[#FDFFF8] font-bold placeholder:text-[#6B7280] shadow-inner resize-none"
            placeholder="Describe the error..."
            rows={3}
          />
        </div>

        {/* 3. Attachment */}
        <div
          className={`p-6 rounded-[1.5rem] border-2 border-dashed ${
            attachments[question.id]?.length > 0
              ? "border-[#AEEC27]/50 bg-[#AEEC27]/5"
              : "border-[#353A47] bg-[#1A1D24]"
          }`}
        >
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-black uppercase tracking-widest text-[#FDFFF8]">
                Proof of Error
              </span>
            </div>
            {attachments[question.id]?.length > 0 && (
              <div className="flex items-center gap-2 text-[#0D0E11] bg-[#AEEC27] px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-[0_0_10px_rgba(174,236,39,0.3)]">
                <Check size={14} strokeWidth={3} /> Attached
              </div>
            )}
          </div>
          <FileUpload
            onFilesSelected={(files) => onFilesSelected(question.id, files)}
            maxFiles={1}
          />
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, ReactNode, useCallback } from "react";

import { useAuth } from "../hooks/useAuth";

import { supabase } from "../lib/supabase";

import { BranchContext, BranchType, ViewMode } from "./BranchContextValue";

import { canSwitchBranches } from "../utils/authUtils";

// Re-export types for convenience
export type { BranchType, ViewMode };

interface BranchProviderProps {
  children: ReactNode;
}

export function BranchProvider({ children }: BranchProviderProps) {
  const { profile, user } = useAuth();

  // Fixed: canAccessBranch initialization order

  const [activeBranch, setActiveBranchState] = useState<BranchType>(() => {
    // Try to get from local storage or default to calicut
    const saved = localStorage.getItem("fets_active_branch");
    return (saved as BranchType) || "calicut";
  });

  const [viewMode, setViewMode] = useState<ViewMode>("single");

  const [branchStatus, setBranchStatus] = useState<{ [key: string]: any }>({});

  const [loading, setLoading] = useState(true);

  const [isSwitching, setIsSwitching] = useState(false);

  // User permissions from profile

  const userBranchAccess = profile?.branch_assigned || "calicut";

  const userAccessLevel = profile?.role || "staff";

  const canAccessBranch = useCallback(
    (branch: BranchType): boolean => {
      if (!profile) return false;
      // Allow all users to access all branches
      return true;
    },
    [profile]
  );

  const loadBranchStatus = useCallback(async () => {
    try {
      const { data, error } = await supabase

        .from("branch_status")

        .select("*")

        .order("branch_name");

      if (error) {
        console.error("Γ¥î Error loading branch status:", error.message);

        return;
      }

      if (data) {
        const statusMap = data.reduce((acc, status) => {
          acc[status.branch_name] = status;

          return acc;
        }, {} as { [key: string]: any });

        setBranchStatus(statusMap);
      }
    } catch (error: any) {
      console.error("Γ¥î Exception loading branch status:", error.message);
    } finally {
      setLoading(false);
    }
  }, []);

  const setActiveBranch = useCallback(
    async (branch: BranchType) => {
      // Only super admins can switch branches after login

      if (!canSwitchBranches(profile?.email, profile?.role)) {
        console.warn("ΓÜá∩╕Å Branch switching is only available to super admins");

        return;
      }

      if (!canAccessBranch(branch) || branch === activeBranch) return;

      // Add switching animation class
      document.body.classList.add("branch-switching");

      setIsSwitching(true);

      try {
        // Update the branch in the database for persistence

        if (user?.id) {
          const { error } = await supabase

            .from("staff_profiles")

            .update({ branch_assigned: branch })

            .eq("user_id", user.id);

          if (error) {
            console.error("Γ¥î Error updating branch:", error.message);

            setIsSwitching(false);
            document.body.classList.remove("branch-switching");

            return;
          }
        }

        // Update state and persistence
        setActiveBranchState(branch);
        localStorage.setItem("fets_active_branch", branch);
      } finally {
        setTimeout(() => {
          setIsSwitching(false);
          document.body.classList.remove("branch-switching");
        }, 600);
      }
    },
    [canAccessBranch, activeBranch, viewMode, profile, user]
  );

  // Load initial branch from user's profile (set at login)
  useEffect(() => {
    if (profile) {
      const defaultBranch =
        profile.branch_assigned === "both"
          ? "calicut"
          : profile.branch_assigned;

      // If no manually saved branch, or (if not super admin) current active branch is not in user's access list, set to default
      const savedBranch = localStorage.getItem("fets_active_branch");
      const isSuper = profile.role === "super_admin";

      if (
        !savedBranch ||
        (!isSuper &&
          profile.branch_assigned !== "both" &&
          profile.branch_assigned !== "global" &&
          savedBranch !== profile.branch_assigned)
      ) {
        setActiveBranchState(defaultBranch as BranchType);
        localStorage.setItem("fets_active_branch", defaultBranch);
      }

      console.log(`≡ƒÅó Synchronized branch from profile: ${activeBranch}`);
    }
  }, [profile]);

  // Load branch status data

  useEffect(() => {
    loadBranchStatus();
  }, [loadBranchStatus]);

  // Set up real-time subscriptions for branch status

  useEffect(() => {
    const subscription = supabase

      .channel("branch-status-changes")

      .on(
        "postgres_changes",

        { event: "*", schema: "public", table: "branch_status" },

        () => {
          console.log("≡ƒöä Branch status updated, reloading...");

          loadBranchStatus();
        }
      )

      .subscribe();

    return () => {
      subscription.unsubscribe();
    };
  }, [loadBranchStatus]);

  const canUseDualMode = (): boolean => {
    return userAccessLevel === "super_admin" || userAccessLevel === "admin";
  };

  const getBranchTheme = (branch: BranchType): string => {
    switch (branch) {
      case "calicut":
        return "branch-calicut";

      case "cochin":
        return "branch-cochin";

      case "kannur":
        return "branch-kannur";

      case "global":
        return "branch-global";

      default:
        return "branch-calicut";
    }
  };

  const value = {
    activeBranch,

    setActiveBranch,

    viewMode,

    setViewMode,

    userBranchAccess,

    userAccessLevel,

    branchStatus,

    loading,

    isSwitching,

    canAccessBranch,

    canUseDualMode,

    getBranchTheme,
  };

  return (
    <BranchContext.Provider value={value}>{children}</BranchContext.Provider>
  );
}

import React, {
  createContext,
  useContext,
  useState,
  ReactNode,
  useEffect,
} from "react";
import { useVideoCall } from "../hooks/useVideoCall";
import { IncomingCallModal } from "../components/Chat/IncomingCallModal";
import { VideoCallOverlay } from "../components/Chat/VideoCallOverlay";
import { AnimatePresence } from "framer-motion";

interface CallContextType {
  callState: any;
  startCall: (
    targetUserIds: string | string[],
    type?: "video" | "audio"
  ) => Promise<void>;
  endCall: () => void;
  answerCall: () => void;
  rejectCall: () => void;
  isMinimized: boolean;
  setIsMinimized: (val: boolean) => void;
}

const CallContext = createContext<CallContextType | undefined>(undefined);

export function CallProvider({ children }: { children: ReactNode }) {
  const { callState, startCall, endCall, answerCall, rejectCall } =
    useVideoCall();
  const [isMinimized, setIsMinimized] = useState(false);

  // Auto-minimize if small screen or navigation occurs (optional logic here)

  return (
    <CallContext.Provider
      value={{
        callState,
        startCall,
        endCall,
        answerCall,
        rejectCall,
        isMinimized,
        setIsMinimized,
      }}
    >
      {children}

      <AnimatePresence>
        {callState.isReceivingCall && (
          <IncomingCallModal
            callerName={callState.callerId!}
            callType={callState.callType}
            onAccept={answerCall}
            onDecline={rejectCall}
          />
        )}
      </AnimatePresence>

      <AnimatePresence>
        {(callState.isInCall || callState.isCalling) && (
          <VideoCallOverlay
            localStream={callState.localStream}
            remoteStreams={callState.remoteStreams}
            onEndCall={endCall}
            isMinimized={isMinimized}
            onToggleMinimize={() => setIsMinimized(!isMinimized)}
            callType={callState.callType}
            startTime={callState.startTime}
          />
        )}
      </AnimatePresence>
    </CallContext.Provider>
  );
}

export function useGlobalCall() {
  const context = useContext(CallContext);
  if (context === undefined) {
    throw new Error("useGlobalCall must be used within a CallProvider");
  }
  return context;
}

import React, { createContext, useContext, useState, ReactNode } from "react";
import { StaffProfile } from "../types/shared";

interface ChatContextType {
  isDetached: boolean;
  setIsDetached: (value: boolean) => void;
  activeUser: StaffProfile | null;
  setActiveUser: (user: StaffProfile | null) => void;
  toggleDetach: () => void;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export function ChatProvider({ children }: { children: ReactNode }) {
  const [isDetached, setIsDetached] = useState(false);
  const [activeUser, setActiveUser] = useState<StaffProfile | null>(null);

  const toggleDetach = () => setIsDetached((prev) => !prev);

  return (
    <ChatContext.Provider
      value={{
        isDetached,
        setIsDetached,
        activeUser,
        setActiveUser,
        toggleDetach,
      }}
    >
      {children}
    </ChatContext.Provider>
  );
}

export function useChat() {
  const context = useContext(ChatContext);
  if (context === undefined) {
    throw new Error("useChat must be used within a ChatProvider");
  }
  return context;
}

import { useState, useRef, useCallback, useEffect } from "react";
import { supabase } from "../lib/supabase";
import { toast } from "react-hot-toast";

interface CallState {
  status: "idle" | "calling" | "ringing" | "connected" | "ended";
  isVideo: boolean;
  isMuted: boolean;
  isVideoOff: boolean;
  remoteUserId: string | null;
  remoteUserName: string | null;
}

interface SignalPayload {
  type:
    | "offer"
    | "answer"
    | "ice-candidate"
    | "call-request"
    | "call-accepted"
    | "call-rejected"
    | "call-ended";
  from: string;
  fromName: string;
  to: string;
  isVideo: boolean;
  sdp?: RTCSessionDescriptionInit;
  candidate?: RTCIceCandidateInit;
}

const ICE_SERVERS: RTCConfiguration = {
  iceServers: [
    // STUN Servers (for basic NAT traversal)
    { urls: "stun:stun.l.google.com:19302" },
    { urls: "stun:stun1.l.google.com:19302" },
    { urls: "stun:stun2.l.google.com:19302" },
    { urls: "stun:stun3.l.google.com:19302" },
    { urls: "stun:stun4.l.google.com:19302" },
    // TURN Servers (for restrictive NAT/firewall environments)
    // Using OpenRelay public TURN servers
    {
      urls: "turn:openrelay.metered.ca:80",
      username: "openrelayproject",
      credential: "openrelayproject",
    },
    {
      urls: "turn:openrelay.metered.ca:443",
      username: "openrelayproject",
      credential: "openrelayproject",
    },
    {
      urls: "turn:openrelay.metered.ca:443?transport=tcp",
      username: "openrelayproject",
      credential: "openrelayproject",
    },
  ],
  iceCandidatePoolSize: 10,
};

export const useWebRTC = (userId: string, userName: string) => {
  const [callState, setCallState] = useState<CallState>({
    status: "idle",
    isVideo: false,
    isMuted: false,
    isVideoOff: false,
    remoteUserId: null,
    remoteUserName: null,
  });

  const [incomingCall, setIncomingCall] = useState<{
    from: string;
    fromName: string;
    isVideo: boolean;
  } | null>(null);

  const peerConnectionRef = useRef<RTCPeerConnection | null>(null);
  const localStreamRef = useRef<MediaStream | null>(null);
  const remoteStreamRef = useRef<MediaStream | null>(null);
  const localVideoRef = useRef<HTMLVideoElement | null>(null);
  const remoteVideoRef = useRef<HTMLVideoElement | null>(null);
  const signalChannelRef = useRef<any>(null);
  const iceCandidatesQueue = useRef<RTCIceCandidateInit[]>([]);

  // Initialize signaling channel
  useEffect(() => {
    if (!userId) return;

    const channel = supabase
      .channel(`webrtc:${userId}`)
      .on("broadcast", { event: "signal" }, ({ payload }) => {
        handleSignal(payload as SignalPayload);
      })
      .subscribe();

    signalChannelRef.current = channel;

    return () => {
      channel.unsubscribe();
    };
  }, [userId]);

  const sendSignal = useCallback(
    async (
      targetUserId: string,
      payload: Omit<SignalPayload, "from" | "fromName" | "to">
    ) => {
      const targetChannel = supabase.channel(`webrtc:${targetUserId}`);
      await targetChannel.subscribe();
      await targetChannel.send({
        type: "broadcast",
        event: "signal",
        payload: {
          ...payload,
          from: userId,
          fromName: userName,
          to: targetUserId,
        },
      });
      targetChannel.unsubscribe();
    },
    [userId, userName]
  );

  const handleSignal = useCallback(
    async (signal: SignalPayload) => {
      if (signal.to !== userId) return;

      switch (signal.type) {
        case "call-request":
          setIncomingCall({
            from: signal.from,
            fromName: signal.fromName,
            isVideo: signal.isVideo,
          });
          break;

        case "call-accepted":
          // Remote accepted, create offer
          await createOffer(signal.from, signal.fromName, signal.isVideo);
          break;

        case "call-rejected":
          toast.error(`${signal.fromName} declined the call`);
          endCall();
          break;

        case "call-ended":
          toast(`${signal.fromName} ended the call`, { icon: "≡ƒô₧" });
          endCall();
          break;

        case "offer":
          if (signal.sdp) {
            await handleOffer(
              signal.from,
              signal.fromName,
              signal.sdp,
              signal.isVideo
            );
          }
          break;

        case "answer":
          if (signal.sdp && peerConnectionRef.current) {
            await peerConnectionRef.current.setRemoteDescription(
              new RTCSessionDescription(signal.sdp)
            );
            // Process queued ICE candidates
            for (const candidate of iceCandidatesQueue.current) {
              await peerConnectionRef.current.addIceCandidate(
                new RTCIceCandidate(candidate)
              );
            }
            iceCandidatesQueue.current = [];
            setCallState((prev) => ({ ...prev, status: "connected" }));
          }
          break;

        case "ice-candidate":
          if (signal.candidate) {
            if (peerConnectionRef.current?.remoteDescription) {
              await peerConnectionRef.current.addIceCandidate(
                new RTCIceCandidate(signal.candidate)
              );
            } else {
              iceCandidatesQueue.current.push(signal.candidate);
            }
          }
          break;
      }
    },
    [userId]
  );

  const createPeerConnection = useCallback(
    (remoteUserId: string) => {
      const pc = new RTCPeerConnection(ICE_SERVERS);

      pc.onicecandidate = (event) => {
        if (event.candidate) {
          sendSignal(remoteUserId, {
            type: "ice-candidate",
            isVideo: callState.isVideo,
            candidate: event.candidate.toJSON(),
          });
        }
      };

      pc.ontrack = (event) => {
        remoteStreamRef.current = event.streams[0];
        if (remoteVideoRef.current) {
          remoteVideoRef.current.srcObject = event.streams[0];
        }
      };

      pc.onconnectionstatechange = () => {
        if (
          pc.connectionState === "disconnected" ||
          pc.connectionState === "failed"
        ) {
          endCall();
        }
      };

      peerConnectionRef.current = pc;
      return pc;
    },
    [sendSignal, callState.isVideo]
  );

  const getLocalStream = useCallback(async (isVideo: boolean) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: true,
        video: isVideo,
      });
      localStreamRef.current = stream;
      if (localVideoRef.current) {
        localVideoRef.current.srcObject = stream;
      }
      return stream;
    } catch (err) {
      toast.error("Failed to access camera/microphone");
      throw err;
    }
  }, []);

  const startCall = useCallback(
    async (targetUserId: string, targetUserName: string, isVideo: boolean) => {
      setCallState({
        status: "calling",
        isVideo,
        isMuted: false,
        isVideoOff: false,
        remoteUserId: targetUserId,
        remoteUserName: targetUserName,
      });

      // Send call request
      await sendSignal(targetUserId, {
        type: "call-request",
        isVideo,
      });

      // Get local stream ready
      await getLocalStream(isVideo);
    },
    [sendSignal, getLocalStream]
  );

  const acceptCall = useCallback(async () => {
    if (!incomingCall) return;

    setCallState({
      status: "ringing",
      isVideo: incomingCall.isVideo,
      isMuted: false,
      isVideoOff: false,
      remoteUserId: incomingCall.from,
      remoteUserName: incomingCall.fromName,
    });

    await getLocalStream(incomingCall.isVideo);

    await sendSignal(incomingCall.from, {
      type: "call-accepted",
      isVideo: incomingCall.isVideo,
    });

    setIncomingCall(null);
  }, [incomingCall, sendSignal, getLocalStream]);

  const rejectCall = useCallback(async () => {
    if (!incomingCall) return;

    await sendSignal(incomingCall.from, {
      type: "call-rejected",
      isVideo: incomingCall.isVideo,
    });

    setIncomingCall(null);
  }, [incomingCall, sendSignal]);

  const createOffer = useCallback(
    async (targetUserId: string, targetUserName: string, isVideo: boolean) => {
      const pc = createPeerConnection(targetUserId);
      const stream = localStreamRef.current;

      if (stream) {
        stream.getTracks().forEach((track) => {
          pc.addTrack(track, stream);
        });
      }

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      await sendSignal(targetUserId, {
        type: "offer",
        isVideo,
        sdp: offer,
      });

      setCallState((prev) => ({ ...prev, status: "ringing" }));
    },
    [createPeerConnection, sendSignal]
  );

  const handleOffer = useCallback(
    async (
      fromUserId: string,
      fromUserName: string,
      sdp: RTCSessionDescriptionInit,
      isVideo: boolean
    ) => {
      const pc = createPeerConnection(fromUserId);
      const stream = localStreamRef.current;

      if (stream) {
        stream.getTracks().forEach((track) => {
          pc.addTrack(track, stream);
        });
      }

      await pc.setRemoteDescription(new RTCSessionDescription(sdp));

      // Process queued ICE candidates
      for (const candidate of iceCandidatesQueue.current) {
        await pc.addIceCandidate(new RTCIceCandidate(candidate));
      }
      iceCandidatesQueue.current = [];

      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);

      await sendSignal(fromUserId, {
        type: "answer",
        isVideo,
        sdp: answer,
      });

      setCallState((prev) => ({ ...prev, status: "connected" }));
    },
    [createPeerConnection, sendSignal]
  );

  const endCall = useCallback(() => {
    if (callState.remoteUserId) {
      sendSignal(callState.remoteUserId, {
        type: "call-ended",
        isVideo: callState.isVideo,
      });
    }

    // Stop all tracks
    localStreamRef.current?.getTracks().forEach((track) => track.stop());
    remoteStreamRef.current?.getTracks().forEach((track) => track.stop());

    // Close peer connection
    peerConnectionRef.current?.close();

    // Reset refs
    localStreamRef.current = null;
    remoteStreamRef.current = null;
    peerConnectionRef.current = null;
    iceCandidatesQueue.current = [];

    setCallState({
      status: "idle",
      isVideo: false,
      isMuted: false,
      isVideoOff: false,
      remoteUserId: null,
      remoteUserName: null,
    });
  }, [callState.remoteUserId, callState.isVideo, sendSignal]);

  const toggleMute = useCallback(() => {
    const audioTrack = localStreamRef.current?.getAudioTracks()[0];
    if (audioTrack) {
      audioTrack.enabled = !audioTrack.enabled;
      setCallState((prev) => ({ ...prev, isMuted: !audioTrack.enabled }));
    }
  }, []);

  const toggleVideo = useCallback(() => {
    const videoTrack = localStreamRef.current?.getVideoTracks()[0];
    if (videoTrack) {
      videoTrack.enabled = !videoTrack.enabled;
      setCallState((prev) => ({ ...prev, isVideoOff: !videoTrack.enabled }));
    }
  }, []);

  return {
    callState,
    incomingCall,
    localVideoRef,
    remoteVideoRef,
    startCall,
    acceptCall,
    rejectCall,
    endCall,
    toggleMute,
    toggleVideo,
  };
};
